#!/usr/bin/env python3
"""IPA Binary Analysis + Entitlements Extractor"""
import struct, hashlib, plistlib, zipfile, os, io, re, json, tempfile

class IPAAnalyzer:
    """Full IPA package analysis: binary, entitlements, provisioning, security assessment"""

    # Mach-O constants
    MH_MAGIC_64 = 0xFEEDFACF
    FAT_MAGIC = 0xCAFEBABE
    LC_CODE_SIGNATURE = 0x1D
    LC_ENCRYPTION_INFO_64 = 0x2C
    LC_LOAD_DYLIB = 0xC
    LC_RPATH = 0x8000001C
    LC_SEGMENT_64 = 0x19

    # CPU types
    CPU_TYPE = {0x100000C: 'arm64', 0x100000D: 'arm64e', 0xC: 'armv7'}

    # Dangerous entitlements (security-relevant)
    DANGEROUS_ENTITLEMENTS = {
        'com.apple.private.security.no-sandbox': 'CRITICAL - No sandbox',
        'com.apple.private.skip-library-validation': 'HIGH - Skip dylib validation',
        'platform-application': 'HIGH - Platform app privileges',
        'com.apple.private.security.no-container': 'HIGH - No container',
        'get-task-allow': 'MEDIUM - Debuggable (should not be in release)',
        'com.apple.developer.team-identifier': 'INFO - Team ID exposed',
        'keychain-access-groups': 'INFO - Keychain access',
        'com.apple.security.application-groups': 'INFO - App group access',
        'com.apple.developer.associated-domains': 'INFO - Universal links',
        'aps-environment': 'INFO - Push notifications',
        'com.apple.developer.networking.vpn.api': 'MEDIUM - VPN capability',
        'com.apple.developer.networking.networkextension': 'MEDIUM - Network extension',
        'com.apple.developer.kernel.increased-memory-limit': 'LOW - Increased memory',
    }

    # Known framework indicators
    FRAMEWORK_INDICATORS = {
        'Firebase': ['FIRApp', 'GoogleService-Info', 'firebase'],
        'React Native': ['RCTBridge', 'RCTRootView', 'jsbundle'],
        'Flutter': ['FlutterViewController', 'flutter_assets', 'App.framework'],
        'Cordova': ['CDVPlugin', 'CDVViewController', 'cordova.js'],
        'Unity': ['UnityFramework', 'UnityAppController', 'Data.unity3d'],
        'Xamarin': ['Xamarin', 'monotouch', 'Mono.framework'],
        'Electron': ['Electron', 'electron.asar'],
        'SwiftUI': ['SwiftUI', '_SwiftUIView'],
        'Objective-C': ['NSObject', 'UIKit'],
    }

    # Suspicious strings to look for
    SUSPICIOUS_PATTERNS = {
        'hardcoded_url': re.compile(rb'https?://[a-zA-Z0-9._/-]{10,}'),
        'api_key': re.compile(rb'(?:api[_-]?key|apikey|token)\s*[=:]\s*["\']?[a-zA-Z0-9]{16,}', re.I),
        'private_key': re.compile(rb'-----BEGIN (?:RSA |EC )?PRIVATE KEY-----'),
        'aws_key': re.compile(rb'AKIA[0-9A-Z]{16}'),
        'base64_blob': re.compile(rb'[A-Za-z0-9+/]{40,}={0,2}'),
        'sqlite_db': re.compile(rb'\.sqlite|\.db|\.realm'),
        'debug_log': re.compile(rb'NSLog\(@|print\(|debugPrint\('),
    }

    def __init__(self):
        self.findings = []
        self.entitlements = {}
        self.provisioning = {}
        self.binary_info = {}
        self.frameworks_detected = []
        self.strings_found = {}

    def analyze_ipa(self, ipa_path):
        """Main analysis entry point"""
        results = {'ipa_path': ipa_path, 'findings': []}

        with zipfile.ZipFile(ipa_path, 'r') as zf:
            # Find the .app bundle
            app_dir = None
            for name in zf.namelist():
                if name.startswith('Payload/') and name.endswith('.app/'):
                    app_dir = name
                    break

            if not app_dir:
                results['error'] = 'No .app bundle found in IPA'
                return results

            results['app_bundle'] = app_dir.rstrip('/')
            results['total_files'] = len(zf.namelist())

            # File size analysis
            total_size = sum(zi.file_size for zi in zf.infolist())
            results['total_size'] = total_size

            # Find and analyze Info.plist
            info_plist_path = app_dir + 'Info.plist'
            if info_plist_path in zf.namelist():
                results['info_plist'] = self._parse_info_plist(zf.read(info_plist_path))

            # Find provisioning profile
            prov_path = app_dir + 'embedded.mobileprovision'
            if prov_path in zf.namelist():
                results['provisioning'] = self._parse_provisioning(zf.read(prov_path))

            # Find and analyze main binary
            if 'info_plist' in results and 'CFBundleExecutable' in results['info_plist']:
                exe_name = results['info_plist']['CFBundleExecutable']
                exe_path = app_dir + exe_name
                if exe_path in zf.namelist():
                    binary_data = zf.read(exe_path)
                    results['binary'] = self._analyze_binary(binary_data)
                    results['entitlements'] = self._extract_entitlements(binary_data)
                    results['strings_analysis'] = self._analyze_strings(binary_data)

            # Framework detection
            results['frameworks'] = self._detect_frameworks(zf, app_dir)

            # File inventory
            results['file_types'] = self._inventory_files(zf, app_dir)

            # Security assessment
            results['security'] = self._security_assessment(results)

        return results

    def _parse_info_plist(self, data):
        """Extract key Info.plist fields"""
        try:
            plist = plistlib.loads(data)
            fields = {}
            keys = ['CFBundleIdentifier', 'CFBundleDisplayName', 'CFBundleName',
                    'CFBundleShortVersionString', 'CFBundleVersion', 'CFBundleExecutable',
                    'MinimumOSVersion', 'LSRequiresIPhoneOS', 'UIDeviceFamily',
                    'CFBundleSupportedPlatforms', 'DTSDKName', 'DTXcodeBuild',
                    'NSAppTransportSecurity', 'UIBackgroundModes',
                    'CFBundleURLTypes', 'LSApplicationQueriesSchemes']
            for k in keys:
                if k in plist:
                    v = plist[k]
                    if isinstance(v, bytes):
                        v = v.hex()
                    fields[k] = v

            # Check ATS exceptions (security-relevant)
            ats = plist.get('NSAppTransportSecurity', {})
            if isinstance(ats, dict):
                if ats.get('NSAllowsArbitraryLoads'):
                    self.findings.append(('HIGH', 'ATS disabled - allows insecure HTTP'))
                exceptions = ats.get('NSExceptionDomains', {})
                if exceptions:
                    fields['ats_exceptions'] = list(exceptions.keys()) if isinstance(exceptions, dict) else []

            # Privacy usage descriptions
            privacy_keys = [k for k in plist if k.startswith('NS') and k.endswith('UsageDescription')]
            if privacy_keys:
                fields['privacy_permissions'] = privacy_keys

            return fields
        except Exception:
            return {'error': 'Failed to parse Info.plist'}

    def _parse_provisioning(self, data):
        """Extract provisioning profile (DER-encoded CMS, plist inside)"""
        result = {}
        # Find embedded plist between XML tags
        start = data.find(b'<?xml')
        end = data.find(b'</plist>')
        if start >= 0 and end >= 0:
            plist_data = data[start:end + 8]
            try:
                prov = plistlib.loads(plist_data)
                result['app_id'] = prov.get('application-identifier', [''])[0] if isinstance(prov.get('application-identifier'), list) else prov.get('application-identifier', '')
                result['team_id'] = prov.get('TeamIdentifier', [''])[0] if isinstance(prov.get('TeamIdentifier'), list) else ''
                result['team_name'] = prov.get('TeamName', '')
                result['name'] = prov.get('Name', '')
                result['creation_date'] = str(prov.get('CreationDate', ''))
                result['expiration_date'] = str(prov.get('ExpirationDate', ''))
                result['provisions_all_devices'] = prov.get('ProvisionsAllDevices', False)

                devices = prov.get('ProvisionedDevices', [])
                result['device_count'] = len(devices) if devices else 0
                result['is_enterprise'] = prov.get('ProvisionsAllDevices', False)
                result['is_development'] = 'get-task-allow' in str(prov.get('Entitlements', {}))

                # Extract entitlements from provisioning
                ent = prov.get('Entitlements', {})
                if ent:
                    result['entitlements'] = {k: str(v) if not isinstance(v, (str, bool, int)) else v for k, v in ent.items()}

                if result['provisions_all_devices']:
                    self.findings.append(('HIGH', 'Enterprise provisioning - no device restrictions'))
                if result['is_development']:
                    self.findings.append(('MEDIUM', 'Development profile - get-task-allow enabled'))

            except Exception:
                result['error'] = 'Failed to parse provisioning profile'
        else:
            result['error'] = 'No plist found in provisioning profile'
        return result

    def _analyze_binary(self, data):
        """Analyze Mach-O binary structure"""
        info = {}
        magic = struct.unpack('<I', data[:4])[0]

        if magic == self.FAT_MAGIC:
            fat_magic = struct.unpack('>I', data[:4])[0]
            nfat = struct.unpack('>I', data[4:8])[0]
            info['type'] = 'Fat Binary'
            info['architectures'] = []
            offset = 8
            for i in range(min(nfat, 4)):
                cpu, sub, arch_off, size, align = struct.unpack('>5I', data[offset:offset+20])
                arch_name = self.CPU_TYPE.get(cpu, hex(cpu))
                info['architectures'].append({'cpu': arch_name, 'offset': arch_off, 'size': size})
                offset += 20
            # Analyze first arch
            if info['architectures']:
                first = info['architectures'][0]
                arch_data = data[first['offset']:first['offset']+first['size']]
                info.update(self._parse_macho(arch_data))
        elif magic == self.MH_MAGIC_64:
            info['type'] = 'Mach-O 64-bit'
            info.update(self._parse_macho(data))
        else:
            info['type'] = 'Unknown'

        return info

    def _parse_macho(self, data):
        """Parse Mach-O header and load commands"""
        info = {}
        if len(data) < 32:
            return info

        magic, cpu, cpusub, ftype, ncmds, sizeofcmds, flags, reserved = struct.unpack('<8I', data[:32])
        info['cpu'] = self.CPU_TYPE.get(cpu, hex(cpu))
        info['ncmds'] = ncmds
        info['encrypted'] = False
        info['pie'] = bool(flags & 0x200000)
        info['dylibs'] = []
        info['segments'] = []
        info['rpaths'] = []
        info['has_code_signature'] = False

        offset = 32
        for _ in range(min(ncmds, 100)):
            if offset + 8 > len(data):
                break
            cmd, cmdsize = struct.unpack('<II', data[offset:offset+8])

            if cmd == self.LC_ENCRYPTION_INFO_64 and offset + 24 <= len(data):
                cryptoff, cryptsize, cryptid = struct.unpack('<3I', data[offset+8:offset+20])
                info['encrypted'] = cryptid != 0
                if info['encrypted']:
                    self.findings.append(('INFO', 'Binary is encrypted (FairPlay DRM)'))

            elif cmd == self.LC_LOAD_DYLIB and offset + cmdsize <= len(data):
                str_off = struct.unpack('<I', data[offset+8:offset+12])[0]
                name_start = offset + str_off
                name_end = data.find(b'\x00', name_start, offset + cmdsize)
                if name_end > name_start:
                    dylib = data[name_start:name_end].decode('utf-8', errors='replace')
                    info['dylibs'].append(dylib)

            elif cmd == self.LC_RPATH and offset + cmdsize <= len(data):
                str_off = struct.unpack('<I', data[offset+8:offset+12])[0]
                name_start = offset + str_off
                name_end = data.find(b'\x00', name_start, offset + cmdsize)
                if name_end > name_start:
                    rpath = data[name_start:name_end].decode('utf-8', errors='replace')
                    info['rpaths'].append(rpath)

            elif cmd == self.LC_SEGMENT_64 and offset + 72 <= len(data):
                segname = data[offset+8:offset+24].split(b'\x00')[0].decode('utf-8', errors='replace')
                vmaddr, vmsize, fileoff, filesize = struct.unpack('<4Q', data[offset+24:offset+56])
                info['segments'].append({'name': segname, 'vmaddr': hex(vmaddr), 'vmsize': vmsize, 'filesize': filesize})

            elif cmd == self.LC_CODE_SIGNATURE:
                info['has_code_signature'] = True

            offset += cmdsize

        # Security checks on dylibs
        for dylib in info['dylibs']:
            if 'FridaGadget' in dylib:
                self.findings.append(('CRITICAL', f'Frida gadget loaded: {dylib}'))
            elif 'cycript' in dylib.lower():
                self.findings.append(('HIGH', f'Cycript detected: {dylib}'))
            elif 'MobileSubstrate' in dylib:
                self.findings.append(('HIGH', f'Substrate hook: {dylib}'))

        if not info['pie']:
            self.findings.append(('HIGH', 'PIE disabled - ASLR not effective'))

        return info

    def _extract_entitlements(self, data):
        """Extract embedded entitlements from binary"""
        entitlements = {}

        # Search for entitlements plist in binary
        markers = [b'<?xml version', b'<!DOCTYPE plist']
        for marker in markers:
            idx = 0
            for _scan in range(100):
                idx = data.find(marker, idx)
                if idx < 0:
                    break
                end = data.find(b'</plist>', idx)
                if end > 0:
                    plist_data = data[idx:end + 8]
                    try:
                        parsed = plistlib.loads(plist_data)
                        if isinstance(parsed, dict):
                            # Check if it looks like entitlements
                            ent_keys = [k for k in parsed if 'com.apple' in k or k in ('get-task-allow', 'application-identifier', 'keychain-access-groups')]
                            if ent_keys:
                                entitlements = parsed
                                break
                    except Exception:
                        pass
                idx += 1

        # Analyze entitlements for security issues
        for ekey, evalue in entitlements.items():
            for epattern, edesc in self.DANGEROUS_ENTITLEMENTS.items():
                if epattern in ekey:
                    eseverity = edesc.split(' - ')[0]
                    self.findings.append((eseverity, f'Entitlement: {ekey} = {evalue}'))

        return entitlements

    def _analyze_strings(self, data):
        """Analyze binary strings for suspicious content"""
        results = {}
        # Only scan TEXT segment or first 5MB
        scan_data = data[:5*1024*1024]

        for name, pattern in self.SUSPICIOUS_PATTERNS.items():
            matches = pattern.findall(scan_data)
            if matches:
                # Deduplicate and limit
                unique = list(set(m.decode('utf-8', errors='replace') if isinstance(m, bytes) else m for m in matches[:50]))
                results[name] = {'count': len(matches), 'samples': unique[:5]}

                if name == 'private_key':
                    self.findings.append(('CRITICAL', f'Private key embedded in binary ({len(matches)} found)'))
                elif name == 'aws_key':
                    self.findings.append(('CRITICAL', f'AWS access key in binary ({len(matches)} found)'))
                elif name == 'api_key':
                    self.findings.append(('HIGH', f'Possible API keys in binary ({len(matches)} found)'))

        return results

    def _detect_frameworks(self, zf, app_dir):
        """Detect frameworks and libraries"""
        detected = []
        all_files = '\n'.join(zf.namelist())

        for framework, indicators in self.FRAMEWORK_INDICATORS.items():
            matches = [ind for ind in indicators if ind in all_files]
            if matches:
                detected.append({'name': framework, 'indicators': matches, 'confidence': len(matches) / len(indicators)})

        # Check Frameworks/ directory
        fw_dir = app_dir + 'Frameworks/'
        frameworks_in_bundle = set()
        for name in zf.namelist():
            if name.startswith(fw_dir) and '.framework/' in name:
                fw_name = name.split(fw_dir)[1].split('.framework/')[0]
                frameworks_in_bundle.add(fw_name)

        return {'detected': detected, 'bundled_frameworks': sorted(frameworks_in_bundle)}

    def _inventory_files(self, zf, app_dir):
        """Categorize files in the IPA"""
        categories = {}
        for zi in zf.infolist():
            if not zi.filename.startswith('Payload/'):
                continue
            ext = os.path.splitext(zi.filename)[1].lower()
            if not ext:
                ext = '(none)'
            if ext not in categories:
                categories[ext] = {'count': 0, 'total_size': 0}
            categories[ext]['count'] += 1
            categories[ext]['total_size'] += zi.file_size
        return dict(sorted(categories.items(), key=lambda x: x[1]['total_size'], reverse=True)[:20])

    def _security_assessment(self, results):
        """Generate security assessment from all findings"""
        assessment = {
            'risk_level': 'LOW',
            'findings': self.findings[:],
            'recommendations': []
        }

        severities = [f[0] for f in self.findings]
        if 'CRITICAL' in severities:
            assessment['risk_level'] = 'CRITICAL'
        elif 'HIGH' in severities:
            assessment['risk_level'] = 'HIGH'
        elif 'MEDIUM' in severities:
            assessment['risk_level'] = 'MEDIUM'

        # Recommendations
        binary = results.get('binary', {})
        if not binary.get('pie'):
            assessment['recommendations'].append('Enable PIE (Position Independent Executable)')
        if not binary.get('has_code_signature'):
            assessment['recommendations'].append('Add code signature')
        if binary.get('encrypted') is False:
            assessment['recommendations'].append('Enable FairPlay encryption for App Store builds')

        ent = results.get('entitlements', {})
        if ent.get('get-task-allow'):
            assessment['recommendations'].append('Disable get-task-allow for release builds')

        info = results.get('info_plist', {})
        ats = info.get('NSAppTransportSecurity', {})
        if isinstance(ats, dict) and ats.get('NSAllowsArbitraryLoads'):
            assessment['recommendations'].append('Enable App Transport Security')

        return assessment


def demo():
    """Build synthetic IPA and analyze it"""
    import tempfile

    print("IPA Binary Analysis + Entitlements Extractor v1.0")
    print("=" * 60)

    # Create synthetic Info.plist
    info_plist = plistlib.dumps({
        'CFBundleIdentifier': 'com.example.secureapp',
