    })

    # Create synthetic entitlements plist
    ent_plist = plistlib.dumps({
        'application-identifier': 'ABCDEF1234.com.example.secureapp',
        'com.apple.developer.team-identifier': 'ABCDEF1234',
        'get-task-allow': True,
        'keychain-access-groups': ['ABCDEF1234.com.example.secureapp'],
        'com.apple.developer.associated-domains': ['applinks:example.com'],
        'aps-environment': 'development',
        'com.apple.developer.networking.vpn.api': ['allow-vpn'],
        'com.apple.security.application-groups': ['group.com.example.secureapp'],
    })

    # Create synthetic provisioning profile (CMS wrapper around plist)
    prov_plist = plistlib.dumps({
        'AppIDName': 'SecureApp',
        'application-identifier': 'ABCDEF1234.com.example.secureapp',
        'TeamIdentifier': ['ABCDEF1234'],
        'TeamName': 'Example Corp',
        'Name': 'SecureApp Development',
        'CreationDate': '2025-01-15T10:30:00Z',
        'ExpirationDate': '2026-01-15T10:30:00Z',
