            'keychain-access-groups': ['ABCDEF1234.*'],
        }
    })
    prov_data = b'\x30\x82' + b'\x00' * 50 + prov_plist + b'\x00' * 20

    # Create synthetic Mach-O binary
    def build_macho():
        # Header: magic, cpu_arm64, subtype, MH_EXECUTE, ncmds, sizeofcmds, flags(PIE), reserved
        ncmds = 5

        # Build load commands
        lcs = b''

        # LC_SEGMENT_64 __TEXT
        segname = b'__TEXT' + b'\x00' * 11
        lc_seg = struct.pack('<2I', 0x19, 72) + segname + struct.pack('<4Q2I2I', 0x100000000, 0x4000, 0, 0x4000, 5, 5, 0, 0)
        lcs += lc_seg

        # LC_SEGMENT_64 __DATA
        segname = b'__DATA' + b'\x00' * 10
        lc_seg = struct.pack('<2I', 0x19, 72) + segname + struct.pack('<4Q2I2I', 0x100004000, 0x4000, 0x4000, 0x1000, 3, 3, 0, 0)
        lcs += lc_seg

        # LC_LOAD_DYLIB /usr/lib/libSystem.B.dylib
        dylib_path = b'/usr/lib/libSystem.B.dylib\x00'
        pad = (4 - (24 + len(dylib_path)) % 4) % 4
        lc_dylib = struct.pack('<2I', 0xC, 24 + len(dylib_path) + pad)
        lc_dylib += struct.pack('<I', 24)  # str offset
        lc_dylib += struct.pack('<I', 2)   # timestamp
        lc_dylib += struct.pack('<I', 0x10000)  # current_version
        lc_dylib += struct.pack('<I', 0x10000)  # compat_version
        lc_dylib += dylib_path + b'\x00' * pad
        lcs += lc_dylib

        # LC_LOAD_DYLIB with suspicious lib
        dylib_path2 = b'/usr/lib/swift/libswiftCore.dylib\x00'
        pad2 = (4 - (24 + len(dylib_path2)) % 4) % 4
        lc_dylib2 = struct.pack('<2I', 0xC, 24 + len(dylib_path2) + pad2)
        lc_dylib2 += struct.pack('<I', 24) + struct.pack('<3I', 2, 0x10000, 0x10000)
        lc_dylib2 += dylib_path2 + b'\x00' * pad2
        lcs += lc_dylib2

        # LC_CODE_SIGNATURE
        lc_sig = struct.pack('<2I', 0x1D, 16) + struct.pack('<2I', 0x8000, 0x200)
        lcs += lc_sig

        sizeofcmds = len(lcs)
        flags = 0x200085  # PIE + DYLDLINK + TWOLEVEL
        header = struct.pack('<8I', 0xFEEDFACF, 0x100000C, 0, 2, ncmds, sizeofcmds, flags, 0)

