        body += b'https://api.example.com/v2/auth\x00'
        body += b'api_key = "sk_live_abc123def456ghi789"\x00'
        body += b'NSLog(@"DEBUG: token = %@"\x00'
        body += b'SecureApp.sqlite\x00'
        body += b'\x00' * 0x100
        body += ent_plist
        body += b'\x00' * 0x500

