#!/usr/bin/env python3
"""macOS Unified Log Parser — Security Event Analyzer"""
import subprocess, os, re, time
from collections import defaultdict

# Security-relevant log categories for threat hunting
SECURITY_CATEGORIES = {
    'authentication': {
        'predicates': [
            'process == "loginwindow"',
            'process == "SecurityAgent"',
            'process == "opendirectoryd"',
            'subsystem == "com.apple.opendirectoryd"',
            'process == "sshd"',
        ],
        'keywords': ['authentication', 'login', 'password', 'credential', 'unlock', 'auth fail'],
        'risk': 'HIGH',
    },
    'process_execution': {
        'predicates': [
            'process == "launchd"',
            'subsystem == "com.apple.xpc.launchd"',
            'process == "amfid"',
        ],
        'keywords': ['spawn', 'exec', 'fork', 'posix_spawn', 'denied', 'killed'],
        'risk': 'HIGH',
    },
    'network': {
        'predicates': [
            'subsystem == "com.apple.network"',
            'process == "mDNSResponder"',
            'process == "configd"',
        ],
        'keywords': ['connection', 'dns', 'resolve', 'socket', 'listen', 'connect'],
        'risk': 'MEDIUM',
    },
    'file_access': {
        'predicates': [
            'subsystem == "com.apple.sandbox"',
            'process == "sandboxd"',
            'process == "fseventsd"',
        ],
        'keywords': ['sandbox', 'deny', 'violation', 'access', 'quarantine'],
        'risk': 'HIGH',
    },
    'code_signing': {
        'predicates': [
            'process == "amfid"',
            'process == "syspolicyd"',
            'subsystem == "com.apple.MobileFileIntegrity"',
        ],
        'keywords': ['signature', 'codesign', 'notarization', 'gatekeeper', 'amfi', 'entitled'],
        'risk': 'CRITICAL',
    },
    'tcc_privacy': {
        'predicates': [
            'process == "tccd"',
            'subsystem == "com.apple.TCC"',
        ],
        'keywords': ['tcc', 'privacy', 'consent', 'camera', 'microphone', 'screen', 'accessibility'],
        'risk': 'HIGH',
    },
    'keychain': {
        'predicates': [
            'process == "securityd"',
            'subsystem == "com.apple.securityd"',
        ],
        'keywords': ['keychain', 'SecItem', 'credential', 'certificate', 'trust'],
        'risk': 'HIGH',
    },
    'kernel': {
        'predicates': [
            'process == "kernel"',
        ],
        'keywords': ['panic', 'kext', 'sandbox', 'mac_', 'policy', 'violation'],
        'risk': 'CRITICAL',
    },
}

# Log message types (Ty column in compact output)
LOG_TYPES = {
    'Df': ('Default', 'INFO'),
    'D':  ('Debug', 'DEBUG'),
    'I':  ('Info', 'INFO'),
    'E':  ('Error', 'ERROR'),
    'F':  ('Fault', 'CRITICAL'),
    'A':  ('Activity', 'INFO'),
    'L':  ('Loss', 'WARNING'),
}


class UnifiedLogParser:
    """Parse and analyze macOS Unified Logs for security events"""

    def __init__(self):
        self.events = []
        self.findings = []

    def query_logs(self, predicate=None, last_minutes=2, max_events=5000):
        """Query unified logs using log show command (READ-ONLY)"""
        cmd = ['/usr/bin/log', 'show', '--last', '%dm' % last_minutes, '--style', 'compact']

        if predicate:
            cmd.extend(['--predicate', predicate])

        try:
            proc = subprocess.run(
                cmd, capture_output=True, text=True, timeout=30
            )
            if proc.returncode != 0 and not proc.stdout:
                return {'error': 'log show failed: ' + proc.stderr[:200], 'events': []}
        except FileNotFoundError:
            return {'error': 'log command not found', 'events': []}
        except subprocess.TimeoutExpired:
            return {'error': 'log show timed out', 'events': []}

        return self._parse_compact_output(proc.stdout, max_events)

    def _parse_compact_output(self, raw_output, max_events=5000):
        """Parse compact format log output"""
        result = {
            'events': [],
            'by_process': defaultdict(int),
            'by_type': defaultdict(int),
            'by_subsystem': defaultdict(int),
            'stats': {},
        }

        lines = raw_output.strip().split('\n')
        if not lines:
            return result

        # Skip header line
        header = lines[0] if lines else ''
        data_lines = lines[1:] if 'Timestamp' in header else lines

        parsed_count = 0
        for line in data_lines:
            if parsed_count >= max_events:
                break

            event = self._parse_compact_line(line)
            if event:
                result['events'].append(event)
                result['by_process'][event['process']] += 1
                result['by_type'][event['type_name']] += 1
                if event.get('subsystem'):
                    result['by_subsystem'][event['subsystem']] += 1
                parsed_count += 1

        result['stats'] = {
            'total_events': len(result['events']),
            'unique_processes': len(result['by_process']),
            'error_count': result['by_type'].get('Error', 0) + result['by_type'].get('Fault', 0),
        }

        return result

    def _parse_compact_line(self, line):
        """Parse a single compact format log line"""
        # Format: 2026-02-15 15:10:21.038 Ty  Process[PID:TID] [subsystem:category] message
        match = re.match(
            r'(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2}\.\d+)\s+(\w+)\s+'
            r'(\w+)\[(\d+):([0-9a-f]+)\]\s+(.*)',
            line
        )
        if not match:
            return None

        timestamp = match.group(1)
        log_type = match.group(2)
        process = match.group(3)
        pid = int(match.group(4))
        tid = match.group(5)
        remainder = match.group(6)

        # Parse subsystem/category if present
        subsystem = ''
        category = ''
        message = remainder
        sub_match = re.match(r'\[([^:]+):([^\]]*)\]\s*(.*)', remainder)
        if sub_match:
            subsystem = sub_match.group(1)
            category = sub_match.group(2)
            message = sub_match.group(3)
        elif remainder.startswith('(') and ')' in remainder:
            paren_match = re.match(r'\(([^)]+)\)\s*(.*)', remainder)
            if paren_match:
                subsystem = paren_match.group(1)
                message = paren_match.group(2)

        type_info = LOG_TYPES.get(log_type, (log_type, 'UNKNOWN'))

        return {
            'timestamp': timestamp,
            'type_code': log_type,
            'type_name': type_info[0],
            'severity': type_info[1],
            'process': process,
            'pid': pid,
            'tid': tid,
            'subsystem': subsystem,
            'category': category,
            'message': message[:500],
        }

    def security_scan(self, last_minutes=2):
        """Scan logs for security-relevant events across all categories"""
        scan_result = {
            'categories': {},
            'total_events': 0,
            'security_events': 0,
            'errors': [],
            'findings': [],
        }

        # Query errors and faults first (most important)
        error_predicate = 'messageType == 16 OR messageType == 17'
        error_result = self.query_logs(predicate=error_predicate, last_minutes=last_minutes, max_events=500)
        if 'error' not in error_result:
            scan_result['categories']['errors_faults'] = {
                'count': len(error_result['events']),
                'events': error_result['events'][:50],
                'top_processes': dict(sorted(error_result['by_process'].items(), key=lambda xx: xx[1], reverse=True)[:10]),
            }
            scan_result['total_events'] += len(error_result['events'])

        # Query each security category
        for cat_name, cat_info in SECURITY_CATEGORIES.items():
            cat_events = []
            for pred in cat_info['predicates'][:2]:
                cat_result = self.query_logs(predicate=pred, last_minutes=last_minutes, max_events=200)
                if 'error' not in cat_result:
                    cat_events.extend(cat_result['events'])

            # Keyword filtering
            keyword_matches = []
            for evt in cat_events:
                msg_lower = evt['message'].lower()
                for kw in cat_info['keywords']:
                    if kw in msg_lower:
                        keyword_matches.append(evt)
                        break

            scan_result['categories'][cat_name] = {
                'count': len(cat_events),
                'keyword_matches': len(keyword_matches),
                'risk': cat_info['risk'],
                'sample_events': cat_events[:10],
            }
            scan_result['total_events'] += len(cat_events)
            scan_result['security_events'] += len(keyword_matches)

            # Generate findings for high-severity matches
            for evt in keyword_matches[:5]:
                if evt['severity'] in ('ERROR', 'CRITICAL'):
                    self.findings.append((cat_info['risk'], '[%s] %s: %s' % (
                        cat_name, evt['process'], evt['message'][:100])))

        scan_result['findings'] = self.findings[:]
        return scan_result


def demo():
    """Run security-focused log analysis"""
    print("macOS Unified Log Parser v1.0")
    print("=" * 60)

    parser = UnifiedLogParser()

    # Basic log query first
    print("\n  Querying recent logs (last 1 minute)...")
    basic = parser.query_logs(last_minutes=1, max_events=2000)

    if 'error' in basic:
        print("  Error: %s" % basic['error'])
        print("\nLog parser ready (no log access)")
        return

    stats = basic['stats']
    print("  Total events: %d" % stats['total_events'])
    print("  Unique processes: %d" % stats['unique_processes'])
    print("  Errors/Faults: %d" % stats['error_count'])

    # Top processes
    print("\n  Top Processes (by event count):")
    top_procs = sorted(basic['by_process'].items(), key=lambda xx: xx[1], reverse=True)[:10]
    for proc_name, count in top_procs:
        print("    %-35s %5d events" % (proc_name, count))

    # Event types
    print("\n  Event Types:")
    for type_name, count in sorted(basic['by_type'].items(), key=lambda xx: xx[1], reverse=True):
        print("    %-15s %5d" % (type_name, count))

    # Top subsystems
    if basic['by_subsystem']:
        print("\n  Top Subsystems:")
        top_subs = sorted(basic['by_subsystem'].items(), key=lambda xx: xx[1], reverse=True)[:10]
        for sub_name, count in top_subs:
            if len(sub_name) > 45:
                sub_name = sub_name[:42] + '...'
            print("    %-45s %5d" % (sub_name, count))

    # Security scan
    print("\n  Security Scan (last 1 minute)...")
    sec = parser.security_scan(last_minutes=1)
    print("  Total events scanned: %d" % sec['total_events'])
    print("  Security-relevant matches: %d" % sec['security_events'])

    print("\n  Security Categories:")
    for cat_name, cat_data in sec['categories'].items():
        count = cat_data.get('count', 0)
        kw_matches = cat_data.get('keyword_matches', 0)
        risk = cat_data.get('risk', '?')
        if count > 0:
            print("    [%s] %-25s %d events (%d keyword matches)" % (risk, cat_name, count, kw_matches))

    # Show error samples
    err_cat = sec['categories'].get('errors_faults', {})
    err_events = err_cat.get('events', [])
    if err_events:
        print("\n  Recent Errors/Faults:")
        seen_msgs = set()
        shown = 0
        for evt in err_events:
            msg_key = evt['process'] + ':' + evt['message'][:50]
            if msg_key not in seen_msgs and shown < 10:
                seen_msgs.add(msg_key)
                msg_short = evt['message'][:80]
                print("    [%s] %s[%d]: %s" % (evt['type_name'], evt['process'], evt['pid'], msg_short))
                shown += 1

    # Show security findings
    if sec['findings']:
        print("\n  Security Findings (%d):" % len(sec['findings']))
        for sev, msg in sec['findings'][:15]:
            print("    [%s] %s" % (sev, msg))

    print("\nUnified log parser ready")


demo()

