    """Analyze dylib injection vectors and hijack opportunities"""

    def __init__(self):
        self.findings = []

    def full_analysis(self, target_binaries=None):
        """Run comprehensive dylib injection analysis"""
        result = {
            'system_state': self._check_system_state(),
            'env_vars': self._check_dyld_env(),
            'binary_analyses': [],
            'hijack_candidates': [],
            'loaded_dylibs': {},
            'stats': {},
        }

        # Default target binaries for analysis
        if target_binaries is None:
            target_binaries = [
                '/bin/ls', '/bin/cat', '/usr/bin/ssh',
                '/usr/bin/python3', '/usr/bin/open',
            ]
            # Add user applications if accessible
            apps_dir = '/Applications'
            if os.path.isdir(apps_dir):
                for app_name in os.listdir(apps_dir):
                    if app_name.endswith('.app'):
                        app_binary = os.path.join(apps_dir, app_name, 'Contents', 'MacOS')
                        if os.path.isdir(app_binary):
                            binaries = [ff for ff in os.listdir(app_binary) if not ff.startswith('.')]
                            if binaries:
                                target_binaries.append(os.path.join(app_binary, binaries[0]))
                                if len(target_binaries) > 15:
                                    break

        # Analyze each binary
        for binary_path in target_binaries:
            if os.path.exists(binary_path):
                analysis = self._analyze_binary(binary_path)
                result['binary_analyses'].append(analysis)

                # Check for hijack opportunities
                hijacks = self._check_hijack_opportunities(analysis)
                if hijacks:
                    result['hijack_candidates'].extend(hijacks)

        # Get currently loaded dylibs for this process
        result['loaded_dylibs'] = self._get_loaded_dylibs()

        # Statistics
        total_binaries = len(result['binary_analyses'])
        total_dylibs = sum(len(ba.get('dylibs', [])) for ba in result['binary_analyses'])
        total_rpaths = sum(len(ba.get('rpaths', [])) for ba in result['binary_analyses'])
        result['stats'] = {
            'binaries_analyzed': total_binaries,
            'total_dylib_deps': total_dylibs,
            'total_rpaths': total_rpaths,
            'hijack_candidates': len(result['hijack_candidates']),
            'sip_enabled': result['system_state'].get('sip_enabled', False),
            'dyld_env_set': len(result['env_vars'].get('set_vars', [])),
        }

        result['findings'] = self.findings[:]
        return result

    def _check_system_state(self):
        """Check SIP, AMFI, and other security state"""
        state = {
            'sip_enabled': True,
            'amfi_enabled': True,
            'hardened_runtime_default': True,
        }

        try:
            proc = subprocess.run(['csrutil', 'status'], capture_output=True, text=True, timeout=5)
            state['sip_status'] = proc.stdout.strip()
            state['sip_enabled'] = 'enabled' in proc.stdout.lower()
        except (FileNotFoundError, subprocess.TimeoutExpired):
            state['sip_status'] = 'Unknown'

        if not state['sip_enabled']:
            self.findings.append(('CRITICAL', 'SIP is DISABLED — dylib injection unrestricted'))

        return state

    def _check_dyld_env(self):
        """Check for DYLD environment variables (injection indicators)"""
        env_result = {
            'set_vars': [],
            'unset_vars': [],
        }

        for var_name, var_info in DYLD_INJECTION_VARS.items():
            val = os.environ.get(var_name)
            if val is not None:
                env_result['set_vars'].append({
                    'name': var_name,
                    'value': val,
                    'risk': var_info['risk'],
                    'desc': var_info['desc'],
                })
                self.findings.append((var_info['risk'], 'DYLD env var set: %s=%s' % (var_name, val[:100])))
            else:
                env_result['unset_vars'].append(var_name)

        return env_result

    def _analyze_binary(self, binary_path):
        """Analyze a binary for dylib dependencies and injection vectors"""
        analysis = {
            'path': binary_path,
            'name': os.path.basename(binary_path),
            'dylibs': [],
            'rpaths': [],
            'weak_dylibs': [],
            'is_hardened': False,
            'has_restrict': False,
            'codesigned': False,
            'entitlements': {},
            'injection_vectors': [],
        }

        # Use otool to get dependencies
        try:
            proc = subprocess.run(
                ['otool', '-L', binary_path],
                capture_output=True, text=True, timeout=10
            )
            for line in proc.stdout.strip().split('\n')[1:]:
                line = line.strip()
                if not line:
                    continue
                # Format: /path/to/dylib (compatibility version X, current version Y)
                dylib_match = re.match(r'(.+?)\s+\((.+)\)', line)
                if dylib_match:
                    dylib_path = dylib_match.group(1).strip()
                    version_info = dylib_match.group(2)
                    analysis['dylibs'].append({
                        'path': dylib_path,
                        'version': version_info,
                        'exists': os.path.exists(dylib_path) if not dylib_path.startswith('@') else None,
                        'uses_rpath': '@rpath' in dylib_path,
                        'uses_loader': '@loader_path' in dylib_path,
                        'uses_exec': '@executable_path' in dylib_path,
                    })
        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass

        # Get rpaths
        try:
            proc = subprocess.run(
                ['otool', '-l', binary_path],
                capture_output=True, text=True, timeout=10
            )
            rpath_next = False
            for line in proc.stdout.split('\n'):
                line_stripped = line.strip()
                if 'cmd LC_RPATH' in line_stripped:
                    rpath_next = True
                elif rpath_next and line_stripped.startswith('path '):
                    rpath = line_stripped.split('path ')[1].split(' (')[0].strip()
                    analysis['rpaths'].append(rpath)
                    rpath_next = False
                elif rpath_next and not line_stripped.startswith('cmdsize'):
                    pass
                else:
                    rpath_next = False
        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass

        # Check code signature and hardened runtime
        try:
            proc = subprocess.run(
                ['codesign', '-dvv', binary_path],
                capture_output=True, text=True, timeout=10
            )
            cs_output = proc.stderr  # codesign outputs to stderr
            analysis['codesigned'] = proc.returncode == 0

            if 'runtime' in cs_output.lower():
                analysis['is_hardened'] = True
            if 'restrict' in cs_output.lower() or 'library-validation' in cs_output.lower():
                analysis['has_restrict'] = True

            # Extract flags
            for line in cs_output.split('\n'):
                if 'flags=' in line:
                    analysis['cs_flags'] = line.split('flags=')[1].strip()
                elif 'CodeDirectory' in line:
                    analysis['cd_info'] = line.strip()
        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass

        # Identify injection vectors
        if not analysis['is_hardened']:
            analysis['injection_vectors'].append('No hardened runtime — DYLD_INSERT_LIBRARIES works')

        if not analysis['has_restrict']:
            analysis['injection_vectors'].append('No library validation — unsigned dylibs can load')

        for dylib in analysis['dylibs']:
            if dylib.get('uses_rpath') and analysis['rpaths']:
                for rpath in analysis['rpaths']:
                    resolved = rpath.replace('@executable_path', os.path.dirname(binary_path))
                    resolved = resolved.replace('@loader_path', os.path.dirname(binary_path))
                    if not os.path.exists(resolved):
                        analysis['injection_vectors'].append('Missing rpath directory: %s (dylib planting)' % resolved)
                        self.findings.append(('HIGH', 'Missing rpath in %s: %s' % (analysis['name'], resolved)))

            if dylib.get('exists') is False:
                analysis['injection_vectors'].append('Missing dylib: %s (dylib proxy/hijack)' % dylib['path'])
                analysis['weak_dylibs'].append(dylib['path'])
                self.findings.append(('HIGH', 'Missing dylib dependency in %s: %s' % (analysis['name'], dylib['path'])))

        return analysis

    def _check_hijack_opportunities(self, analysis):
        """Check for dylib hijack opportunities in a binary"""
        hijacks = []

        # @rpath hijacking: if rpath dirs are writable, attacker can plant dylibs
        for rpath in analysis.get('rpaths', []):
            resolved = rpath.replace('@executable_path', os.path.dirname(analysis['path']))
            resolved = resolved.replace('@loader_path', os.path.dirname(analysis['path']))
            if os.path.exists(resolved):
                try:
                    if os.access(resolved, os.W_OK):
                        hijacks.append({
                            'binary': analysis['name'],
                            'type': 'rpath_writable',
                            'path': resolved,
                            'risk': 'HIGH',
                            'desc': 'Writable rpath directory — can plant dylib proxies',
                        })
                        self.findings.append(('HIGH', 'Writable rpath in %s: %s' % (analysis['name'], resolved)))
                except OSError:
                    pass

        # Missing dylib hijacking
        for dylib in analysis.get('dylibs', []):
            if dylib.get('exists') is False:
                hijacks.append({
                    'binary': analysis['name'],
                    'type': 'missing_dylib',
                    'path': dylib['path'],
                    'risk': 'HIGH',
                    'desc': 'Missing dylib — can be replaced with malicious version',
                })

        return hijacks

    def _get_loaded_dylibs(self):
        """Get dylibs loaded in the current process"""
        loaded = {}
        try:
            proc = subprocess.run(
                ['vmmap', '-summary', str(os.getpid())],
                capture_output=True, text=True, timeout=10
            )
            dylib_count = 0
            for line in proc.stdout.split('\n'):
                if '.dylib' in line or '.framework' in line:
                    dylib_count += 1
            loaded['summary_dylib_refs'] = dylib_count
        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass

        # Alternative: use otool on ourselves
        try:
            python_path = subprocess.run(['which', 'python3'], capture_output=True, text=True).stdout.strip()
            if python_path and os.path.exists(python_path):
                proc = subprocess.run(
                    ['otool', '-L', python_path],
                    capture_output=True, text=True, timeout=10
                )
                loaded['python_dylibs'] = []
                for line in proc.stdout.strip().split('\n')[1:]:
                    line = line.strip()
                    dylib_match = re.match(r'(.+?)\s+\(', line)
                    if dylib_match:
                        loaded['python_dylibs'].append(dylib_match.group(1).strip())
        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass

        return loaded


def demo():
    """Run dylib injection analysis on real system"""
    print("macOS Dylib Injection Engine v1.0")
    print("=" * 60)

    engine = DylibInjectionEngine()
    result = engine.full_analysis()

    # System state
    sys_state = result['system_state']
    print("\n  System Security State:")
    print("    SIP: %s" % ('ENABLED' if sys_state['sip_enabled'] else 'DISABLED'))
    print("    SIP Status: %s" % sys_state.get('sip_status', 'Unknown'))
    print("    AMFI: %s" % ('Enabled' if sys_state.get('amfi_enabled') else 'Unknown'))

    # DYLD environment
    env = result['env_vars']
    if env['set_vars']:
        print("\n  [!] DYLD Environment Variables SET:")
        for var in env['set_vars']:
            print("    [%s] %s = %s" % (var['risk'], var['name'], var['value'][:60]))
    else:
        print("\n  DYLD Environment: Clean (no injection vars set)")

    # Binary analyses
    stats = result['stats']
    print("\n  Binaries Analyzed: %d" % stats['binaries_analyzed'])
    print("  Total Dylib Dependencies: %d" % stats['total_dylib_deps'])
    print("  Total RPaths: %d" % stats['total_rpaths'])
    print("  Hijack Candidates: %d" % stats['hijack_candidates'])

    print("\n  Binary Details:")
    for ba in result['binary_analyses']:
        name = ba['name']
        dylib_count = len(ba['dylibs'])
        rpath_count = len(ba['rpaths'])
        hardened = 'Hardened' if ba['is_hardened'] else 'NOT hardened'
        restrict = '+LibVal' if ba['has_restrict'] else ''
        codesigned = 'Signed' if ba['codesigned'] else 'UNSIGNED'
        vectors = len(ba['injection_vectors'])

        if len(name) > 25:
            name = name[:22] + '...'
        print("    %-25s %d dylibs, %d rpaths | %s %s %s | %d vectors" % (
            name, dylib_count, rpath_count, codesigned, hardened, restrict, vectors))

        # Show injection vectors for interesting binaries
        if ba['injection_vectors'] and not ba['path'].startswith('/System/'):
            for vec in ba['injection_vectors'][:2]:
                print("      -> %s" % vec[:80])

    # Hijack opportunities
    if result['hijack_candidates']:
        print("\n  Hijack Opportunities (%d):" % len(result['hijack_candidates']))
        for hj in result['hijack_candidates'][:10]:
            print("    [%s] %s: %s" % (hj['risk'], hj['binary'], hj['desc']))
            print("         Path: %s" % hj['path'])

    # Loaded dylibs
    loaded = result['loaded_dylibs']
    if loaded.get('python_dylibs'):
        print("\n  Python Process Dylibs (%d):" % len(loaded['python_dylibs']))
        for dylib in loaded['python_dylibs'][:8]:
            print("    %s" % dylib)

    # Findings
    if result['findings']:
        print("\n  Security Findings (%d):" % len(result['findings']))
        for sev, msg in result['findings'][:15]:
            print("    [%s] %s" % (sev, msg))

    print("\nDylib injection engine ready")


