                            svc_name = TCC_CRITICAL_SERVICES.get(service, service)
                            check_result['details'].append('%s allows DYLD env vars + has %s' % (grant['client'], svc_name))

        # Generic applicability for remaining techniques
        if tech_id in ('mount_apfs_snapshot', 'spotlight_importer_injection',
                       'calendar_tcc_bypass', 'plugin_loading_abuse', 'icloud_tcc_bypass'):
            check_result['details'].append('Technique documented — requires manual verification')

        return check_result

    def _check_app_hardened(self, bundle_id):
        """Check if an app has hardened runtime"""
        # Try to find app path from bundle ID
        app_paths = ['/Applications', os.path.expanduser('~/Applications')]
        for app_dir in app_paths:
            if not os.path.isdir(app_dir):
                continue
            for app_name in os.listdir(app_dir):
                if not app_name.endswith('.app'):
                    continue
                info_plist = os.path.join(app_dir, app_name, 'Contents', 'Info.plist')
                if os.path.exists(info_plist):
                    try:
                        with open(info_plist, 'rb') as pf:
                            plist = plistlib.load(pf)
                        if plist.get('CFBundleIdentifier') == bundle_id:
                            # Found the app, check codesign
                            exec_name = plist.get('CFBundleExecutable', '')
                            exec_path = os.path.join(app_dir, app_name, 'Contents', 'MacOS', exec_name)
                            if os.path.exists(exec_path):
                                proc = subprocess.run(
                                    ['codesign', '-dvv', exec_path],
                                    capture_output=True, text=True, timeout=5
                                )
                                return 'runtime' in proc.stderr.lower()
                    except Exception:
                        pass
        return None

    def _check_app_entitlement(self, bundle_id, entitlement):
        """Check if an app has a specific entitlement"""
        # Simplified check via codesign
        return False  # Would need full app path resolution

    def _find_vulnerable_apps(self, tcc_grants):
        """Find apps with TCC grants that have injection vectors"""
        vulnerable = []
        checked = set()

        for service, grants in tcc_grants.items():
            for grant in grants:
                client = grant['client']
                if client in checked:
                    continue
                checked.add(client)

                if grant['client_type'] == 'BundleID':
                    hardened = self._check_app_hardened(client)
                    if hardened is False:
                        svc_name = TCC_CRITICAL_SERVICES.get(service, service)
                        vulnerable.append({
                            'bundle_id': client,
                            'service': svc_name,
                            'vector': 'DYLD_INSERT_LIBRARIES (no hardened runtime)',
                            'risk': 'CRITICAL',
                        })

        return vulnerable


