#!/usr/bin/env python3
"""macOS AMFI Policy Parser — Kernel Code Signing Enforcement Analyzer"""
import os, subprocess, re
from collections import defaultdict
from pathlib import Path

# AMFI sysctl policy keys and their security implications
AMFI_POLICY_KEYS = {
    'trust_cache_interface': {
        'desc': 'Trust cache version (static trust cache for platform binaries)',
        'secure_values': [3],
        'risk': 'Older versions may have bypass vulnerabilities',
    },
    'force_policy': {
        'desc': 'Force code signing policy even in permissive mode',
        'secure_values': [0, 1],
        'risk': 'Controls whether AMFI enforces signatures on all code',
    },
    'developer_mode_status': {
        'desc': 'Developer Mode enabled (allows unsigned code for development)',
        'secure_values': [0],
        'risk': 'CRITICAL: Developer Mode allows running unsigned/modified code',
    },
    'developer_mode_resolved': {
        'desc': 'Developer mode state has been resolved by system',
        'secure_values': [0, 1],
        'risk': 'Indicates system has determined developer mode state',
    },
    'launch_constraints_enforced': {
        'desc': 'Launch constraints enforcement (macOS 13+)',
        'secure_values': [1],
        'risk': 'Disabling allows process launch constraint bypass',
    },
    'launch_constraints_3rd_party_allowed': {
        'desc': 'Third-party apps can set launch constraints',
        'secure_values': [0, 1],
        'risk': 'Controls launch constraint scope',
    },
    'launch_constraints_cc_types_enforced': {
        'desc': 'Launch constraint CC type bitmask (15 = all enforced)',
        'secure_values': [15],
        'risk': 'Lower values mean some constraint types are not enforced',
    },
    'verbose_logging': {
        'desc': 'AMFI verbose logging enabled',
        'secure_values': [0],
        'risk': 'Verbose logging may leak sensitive code signing info',
    },
    'hsp_enable': {
        'desc': 'Hardened sandbox process enforcement',
        'secure_values': [1],
        'risk': 'Disabling weakens process sandboxing',
    },
    'allow_only_platform_code': {
        'desc': 'Only allow Apple-signed platform code',
        'secure_values': [0],
        'risk': 'When 1, blocks all third-party code (recovery mode)',
    },
    'platform_policy': {
        'desc': 'Platform code signing policy active',
        'secure_values': [1],
        'risk': 'Disabling removes platform binary verification',
    },
    'exec_requires_trustcache': {
        'desc': 'Execution requires trust cache entry',
        'secure_values': [0],
        'risk': 'When 1, only trust-cached binaries can execute',
    },
    'unsigned_code_policy': {
        'desc': 'Policy for unsigned code (1 = kill)',
        'secure_values': [1],
        'risk': 'Value 0 allows unsigned code execution',
    },
    'forced_cs_kill': {
        'desc': 'Kill processes with invalid code signatures',
        'secure_values': [1],
        'risk': 'Disabling allows tampered binaries to continue',
    },
    'qa_root_certs_allowed': {
        'desc': 'QA/test root certificates accepted',
        'secure_values': [0],
        'risk': 'CRITICAL: Allowing QA certs enables signing bypass',
    },
}

# Code signing flag meanings
CS_FLAGS = {
    0x00000: 'none',
    0x00001: 'valid',
    0x00002: 'adhoc',
    0x00004: 'get_task_allow',
    0x00008: 'installer',
    0x00010: 'forced_lv',
    0x00020: 'invalid_allowed',
    0x00100: 'hard',
    0x00200: 'kill',
    0x00400: 'check_expiration',
    0x00800: 'restrict',
    0x01000: 'enforcement',
    0x02000: 'require_lv',
    0x04000: 'entitlements_validated',
    0x08000: 'nvram_unrestricted',
    0x10000: 'runtime',
    0x20000: 'linker_signed',
}

# Code Directory versions
CD_VERSIONS = {
    0x20001: 'v2.0.1 (macOS 10.0)',
    0x20100: 'v2.1 (macOS 10.6)',
    0x20200: 'v2.2 (macOS 10.9)',
    0x20300: 'v2.3 (macOS 10.11)',
    0x20400: 'v2.4 (macOS 10.12+)',
    0x20500: 'v2.5 (macOS 11+)',
    0x20600: 'v2.6 (macOS 14+)',
}


class AMFIPolicyAnalyzer:
    """Analyze AMFI kernel code signing policies"""

    def __init__(self):
        self.findings = []

    def full_analysis(self):
        """Run complete AMFI policy analysis"""
        result = {
            'sip_status': self._check_sip(),
            'amfi_policies': self._parse_amfi_sysctl(),
            'amfid_info': self._check_amfid(),
            'binary_analysis': [],
            'codesign_stats': {},
            'boot_args': self._check_boot_args(),
        }

        # Analyze system binaries for code signing policy
        target_bins = [
            '/usr/bin/python3', '/usr/bin/ssh', '/usr/bin/curl', '/usr/bin/git',
            '/bin/bash', '/bin/zsh', '/usr/bin/open', '/usr/bin/security',
            '/usr/sbin/spctl', '/usr/libexec/amfid', '/usr/bin/ditto',
            '/usr/bin/hdiutil', '/usr/bin/xattr', '/usr/bin/csrutil',
            '/usr/bin/codesign', '/usr/bin/xcrun', '/usr/bin/swift',
            '/usr/sbin/softwareupdate', '/usr/bin/sudo', '/usr/bin/su',
        ]

        # Also scan /Applications for third-party app binaries
        apps_dir = '/Applications'
        app_count = 0
        if os.path.isdir(apps_dir):
            for app_name in sorted(os.listdir(apps_dir)):
                if app_name.endswith('.app') and app_count < 15:
                    app_binary = os.path.join(apps_dir, app_name, 'Contents', 'MacOS')
                    if os.path.isdir(app_binary):
                        for bin_name in os.listdir(app_binary):
                            bin_path = os.path.join(app_binary, bin_name)
                            if os.path.isfile(bin_path) and not bin_name.startswith('.'):
                                target_bins.append(bin_path)
                                app_count += 1
                                break

        for bin_path in target_bins:
            if os.path.isfile(bin_path):
                analysis = self._analyze_binary_signing(bin_path)
                if analysis:
                    result['binary_analysis'].append(analysis)

        # Compute statistics
        total = len(result['binary_analysis'])
        runtime_count = sum(1 for ba in result['binary_analysis'] if ba.get('hardened_runtime'))
        no_runtime = sum(1 for ba in result['binary_analysis'] if not ba.get('hardened_runtime'))
        adhoc = sum(1 for ba in result['binary_analysis'] if ba.get('adhoc_signed'))
        platform = sum(1 for ba in result['binary_analysis'] if ba.get('platform_binary'))
        unsigned = sum(1 for ba in result['binary_analysis'] if not ba.get('signed'))

        result['codesign_stats'] = {
            'total_analyzed': total,
            'hardened_runtime': runtime_count,
            'no_hardened_runtime': no_runtime,
            'adhoc_signed': adhoc,
            'platform_binaries': platform,
            'unsigned': unsigned,
        }

        # Check for weakened AMFI policies
        for policy_key, policy_val in result['amfi_policies'].items():
            base_key = policy_key.replace('security.mac.amfi.', '')
            if base_key in AMFI_POLICY_KEYS:
                meta = AMFI_POLICY_KEYS[base_key]
                if policy_val not in meta['secure_values']:
                    severity = 'CRITICAL' if 'CRITICAL' in meta['risk'] else 'HIGH'
                    self.findings.append((severity, 'AMFI %s = %s — %s' % (base_key, policy_val, meta['risk'])))

        result['findings'] = self.findings[:]
        return result

    def _check_sip(self):
        """Check System Integrity Protection status"""
        status = {'enabled': True, 'raw': ''}
        try:
            proc = subprocess.run(
                ['csrutil', 'status'],
                capture_output=True, text=True, timeout=5
            )
            status['raw'] = proc.stdout.strip()
            status['enabled'] = 'enabled' in proc.stdout.lower()
            if not status['enabled']:
                self.findings.append(('CRITICAL', 'SIP is DISABLED — AMFI enforcement weakened'))
        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass
        return status

    def _parse_amfi_sysctl(self):
        """Parse AMFI sysctl values"""
        policies = {}
        try:
            proc = subprocess.run(
                ['sysctl', 'security.mac.amfi'],
                capture_output=True, text=True, timeout=5
            )
            for line in proc.stdout.split('\n'):
                if ':' in line:
                    key_val = line.split(':', 1)
                    key_name = key_val[0].strip()
                    try:
                        val = int(key_val[1].strip())
                    except (ValueError, IndexError):
                        val = key_val[1].strip() if len(key_val) > 1 else ''
                    policies[key_name] = val
        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass
        return policies

    def _check_amfid(self):
        """Check amfid daemon status"""
        info = {
            'running': False,
            'pid': 0,
            'path': '/usr/libexec/amfid',
            'entitlements': [],
        }

        # Check if running
        try:
            proc = subprocess.run(
                ['pgrep', '-x', 'amfid'],
                capture_output=True, text=True, timeout=5
            )
            if proc.returncode == 0:
                info['running'] = True
                info['pid'] = int(proc.stdout.strip().split('\n')[0])
        except (FileNotFoundError, subprocess.TimeoutExpired, ValueError):
            pass

        # Check entitlements
        if os.path.isfile(info['path']):
            try:
                proc = subprocess.run(
                    ['codesign', '-d', '--entitlements', '-', info['path']],
                    capture_output=True, text=True, timeout=10
                )
                for line in proc.stdout.split('\n'):
                    line_stripped = line.strip()
                    if line_stripped.startswith('[Key]'):
                        ent_key = line_stripped.replace('[Key] ', '')
                        info['entitlements'].append(ent_key)
            except (FileNotFoundError, subprocess.TimeoutExpired):
                pass

        return info

    def _check_boot_args(self):
        """Check kernel boot arguments for AMFI-related flags"""
        boot_info = {'raw': '', 'amfi_disabled': False, 'cs_disabled': False}
        try:
            proc = subprocess.run(
                ['sysctl', 'kern.bootargs'],
                capture_output=True, text=True, timeout=5
            )
            boot_info['raw'] = proc.stdout.strip()
            args_lower = boot_info['raw'].lower()
            boot_info['amfi_disabled'] = 'amfi_get_out_of_my_way=1' in args_lower
            boot_info['cs_disabled'] = 'cs_enforcement_disable=1' in args_lower
            if boot_info['amfi_disabled']:
                self.findings.append(('CRITICAL', 'AMFI disabled via boot-args'))
            if boot_info['cs_disabled']:
                self.findings.append(('CRITICAL', 'Code signing enforcement disabled via boot-args'))
        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass
        return boot_info

    def _analyze_binary_signing(self, bin_path):
        """Analyze code signing properties of a binary"""
        info = {
            'path': bin_path,
            'name': os.path.basename(bin_path),
            'signed': False,
            'hardened_runtime': False,
            'adhoc_signed': False,
            'platform_binary': False,
            'cd_version': '',
            'cd_version_name': '',
            'flags_raw': '',
            'flags_parsed': [],
            'runtime_version': '',
            'hash_count': 0,
            'signature_size': 0,
        }

        try:
            proc = subprocess.run(
                ['codesign', '-dvvv', bin_path],
                capture_output=True, text=True, timeout=10
            )
            cs_out = proc.stderr
            info['signed'] = proc.returncode == 0

            if info['signed']:
                for line in cs_out.split('\n'):
                    if 'CodeDirectory' in line and 'flags=' in line:
                        # Parse CD version
                        ver_match = re.search(r'v=(\w+)', line)
                        if ver_match:
                            try:
                                cd_ver = int(ver_match.group(1), 16)
                                info['cd_version'] = ver_match.group(1)
                                info['cd_version_name'] = CD_VERSIONS.get(cd_ver, 'Unknown')
                            except ValueError:
                                info['cd_version'] = ver_match.group(1)

                        # Parse flags
                        flags_match = re.search(r'flags=0x(\w+)\(([^)]*)\)', line)
                        if flags_match:
                            flags_val = int(flags_match.group(1), 16)
                            info['flags_raw'] = '0x%x(%s)' % (flags_val, flags_match.group(2))
                            # Parse individual flags
                            for flag_bit, flag_name in CS_FLAGS.items():
                                if flag_bit and (flags_val & flag_bit):
                                    info['flags_parsed'].append(flag_name)
                            info['hardened_runtime'] = bool(flags_val & 0x10000)

                        # Parse hash count
                        hash_match = re.search(r'hashes=(\d+)\+(\d+)', line)
                        if hash_match:
                            info['hash_count'] = int(hash_match.group(1))

                    elif line.strip().startswith('Runtime Version='):
                        info['runtime_version'] = line.split('=')[1].strip()

                    elif line.strip().startswith('Signature size='):
                        try:
                            info['signature_size'] = int(line.split('=')[1].strip())
                        except ValueError:
                            pass

                    elif 'Authority=Software Signing' in line:
                        info['platform_binary'] = True

                    elif 'Info.plist=not bound' in line or 'Signature=adhoc' in line:
                        info['adhoc_signed'] = True

                # Determine if ad-hoc by checking for adhoc flag
                if not info['flags_parsed'] and info['signed']:
                    # flags=0x0(none) means no special flags
                    pass

                # Security assessment
                if not info['hardened_runtime'] and '/Applications/' in bin_path:
                    self.findings.append(('MEDIUM', 'No hardened runtime: %s' % info['name']))

        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass

        return info


def demo():
    """Run AMFI policy analysis"""
    print("macOS AMFI Policy Parser v1.0")
    print("=" * 60)

    analyzer = AMFIPolicyAnalyzer()
    result = analyzer.full_analysis()

    # SIP status
    sip = result['sip_status']
    print("\n  SIP: %s" % ('ENABLED' if sip['enabled'] else 'DISABLED'))

    # Boot args
    boot = result['boot_args']
    print("  Boot args: %s" % (boot['raw'] or '(empty)'))
    if boot['amfi_disabled']:
        print("  [CRITICAL] AMFI disabled via boot-args!")
    if boot['cs_disabled']:
        print("  [CRITICAL] Code signing disabled via boot-args!")

    # amfid daemon
    amfid = result['amfid_info']
    print("\n  amfid daemon: %s (PID %d)" % ('RUNNING' if amfid['running'] else 'NOT RUNNING', amfid['pid']))
    if amfid['entitlements']:
        print("  amfid entitlements (%d):" % len(amfid['entitlements']))
        for ent in amfid['entitlements']:
            print("    %s" % ent)

    # AMFI policies
    policies = result['amfi_policies']
    print("\n  AMFI Kernel Policies (%d):" % len(policies))
    for policy_key in sorted(policies.keys()):
        base_key = policy_key.replace('security.mac.amfi.', '')
        policy_val = policies[policy_key]
        meta = AMFI_POLICY_KEYS.get(base_key, {})
        desc = meta.get('desc', '')[:50] if meta else ''
        secure_vals = meta.get('secure_values', [])
        status_tag = 'OK' if policy_val in secure_vals else 'WARN' if meta else '----'
        print("    [%4s] %-40s = %-3s  %s" % (status_tag, base_key, policy_val, desc))

    # Code signing statistics
    stats = result['codesign_stats']
    print("\n  Code Signing Statistics:")
    print("    Total binaries analyzed: %d" % stats['total_analyzed'])
    print("    Hardened runtime: %d" % stats['hardened_runtime'])
    print("    No hardened runtime: %d" % stats['no_hardened_runtime'])
    print("    Platform binaries: %d" % stats['platform_binaries'])
    print("    Unsigned: %d" % stats['unsigned'])

    # Binary details
    print("\n  Binary Analysis:")
    print("    %-30s %-8s %-7s %-6s %s" % ('Binary', 'CD Ver', 'Runtime', 'Plat', 'Flags'))
    for ba in result['binary_analysis']:
        name = ba['name']
        if len(name) > 30:
            name = name[:27] + '...'
        cd_ver = ba.get('cd_version', '?')
        runtime_tag = 'Hard' if ba['hardened_runtime'] else '----'
        plat_tag = 'Plat' if ba['platform_binary'] else '----'
        flags_str = ','.join(ba['flags_parsed'][:3]) if ba['flags_parsed'] else 'none'
        print("    %-30s %-8s %-7s %-6s %s" % (name, cd_ver, runtime_tag, plat_tag, flags_str))

    # Findings
    if result['findings']:
        print("\n  Security Findings (%d):" % len(result['findings']))
        for sev, msg in result['findings'][:20]:
            print("    [%s] %s" % (sev, msg))

    print("\nAMFI policy parser ready")


demo()

