                       'lsopen', 'user-preference*', 'authorization-right-obtain',
                       'appleevent-send'],
        'risk': 'System-level operations',
        'mitre': ['T1106'],
    },
}

# Security-sensitive entitlement to SBPL mapping
ENTITLEMENT_SBPL_MAP = {
    'com.apple.security.device.microphone': 'audio-input',
    'com.apple.security.device.camera': 'camera',
    'com.apple.security.personal-information.addressbook': 'addressbook',
    'com.apple.security.personal-information.calendars': 'calendar',
    'com.apple.security.personal-information.location': 'location',
    'com.apple.security.files.user-selected.read-only': 'file-read',
    'com.apple.security.files.user-selected.read-write': 'file-write',
    'com.apple.security.network.client': 'network-outbound',
    'com.apple.security.network.server': 'network-inbound',
}


class SandboxProfileAnalyzer:
    """Analyze macOS sandbox profiles (SBPL)"""

    def __init__(self):
        self.findings = []

    def full_analysis(self):
        """Run complete sandbox profile analysis"""
        result = {
            'system_profiles': self._analyze_system_profiles(),
            'app_containers': self._analyze_app_containers(),
            'profile_stats': {},
            'operation_coverage': defaultdict(int),
            'security_assessment': [],
            'high_risk_profiles': [],
        }

        # Compute operation coverage across all profiles
        for prof in result['system_profiles']:
            for op_name, op_count in prof.get('operations', {}).items():
                result['operation_coverage'][op_name] += op_count

        # Identify high-risk profiles
        for prof in result['system_profiles']:
            risk_score = self._compute_risk_score(prof)
            prof['risk_score'] = risk_score
            if risk_score >= 7:
                result['high_risk_profiles'].append(prof)

        # Statistics
        total_profiles = len(result['system_profiles'])
        total_allow = sum(pp.get('allow_count', 0) for pp in result['system_profiles'])
        total_deny = sum(pp.get('deny_count', 0) for pp in result['system_profiles'])
        total_imports = sum(len(pp.get('imports', [])) for pp in result['system_profiles'])

        result['profile_stats'] = {
            'total_profiles': total_profiles,
            'total_allow_rules': total_allow,
            'total_deny_rules': total_deny,
            'total_imports': total_imports,
            'app_containers': len(result['app_containers']),
            'high_risk': len(result['high_risk_profiles']),
            'unique_operations': len(result['operation_coverage']),
        }

        result['findings'] = self.findings[:]
        return result

    def _analyze_system_profiles(self):
        """Parse all system sandbox profiles"""
        profiles = []
        profiles_dir = '/System/Library/Sandbox/Profiles'
        if not os.path.isdir(profiles_dir):
            return profiles

        profile_files = sorted([ff for ff in os.listdir(profiles_dir) if ff.endswith('.sb')])

        for prof_file in profile_files:
            prof_path = os.path.join(profiles_dir, prof_file)
            prof_data = self._parse_profile(prof_path)
            if prof_data:
                profiles.append(prof_data)

        return profiles

    def _parse_profile(self, path):
        """Parse a single SBPL profile"""
        prof = {
            'path': path,
            'name': os.path.basename(path).replace('.sb', ''),
            'lines': 0,
            'allow_count': 0,
            'deny_count': 0,
            'imports': [],
            'operations': defaultdict(int),
            'allows_network': False,
            'allows_exec': False,
            'allows_file_write': False,
            'allows_dynamic_code': False,
            'allows_mach_lookup': False,
            'denies_default': False,
            'version': 0,
            'mach_services': [],
            'file_paths': [],
            'subpaths': [],
        }

        try:
            with open(path, 'r') as fh:
                content = fh.read()
                prof['lines'] = len(content.split('\n'))

                for line in content.split('\n'):
                    stripped = line.strip()

                    # Skip comments
                    if stripped.startswith(';') or not stripped:
                        continue

                    # Version
                    if stripped.startswith('(version'):
                        ver_match = re.search(r'\(version\s+(\d+)\)', stripped)
                        if ver_match:
                            prof['version'] = int(ver_match.group(1))

                    # Imports
                    if stripped.startswith('(import'):
                        imp_match = re.search(r'\(import\s+"([^"]+)"\)', stripped)
                        if imp_match:
                            prof['imports'].append(imp_match.group(1))

                    # Count allows and denies
                    if '(allow' in stripped:
                        prof['allow_count'] += 1
                        # Check what's allowed
                        if 'network-outbound' in stripped or 'network-inbound' in stripped or 'network*' in stripped:
                            prof['allows_network'] = True
                        if 'process-exec' in stripped:
                            prof['allows_exec'] = True
                        if 'file-write' in stripped:
                            prof['allows_file_write'] = True
                        if 'dynamic-code-generation' in stripped:
                            prof['allows_dynamic_code'] = True
                        if 'mach-lookup' in stripped:
                            prof['allows_mach_lookup'] = True

                    if '(deny' in stripped:
                        prof['deny_count'] += 1
                        if 'deny default' in stripped:
                            prof['denies_default'] = True

                    # Extract mach service names
                    mach_matches = re.findall(r'global-name\s+"([^"]+)"', stripped)
                    for mm in mach_matches:
                        if mm not in prof['mach_services']:
                            prof['mach_services'].append(mm)

                    # Extract file paths
                    subpath_matches = re.findall(r'subpath\s+"([^"]+)"', stripped)
                    for sp in subpath_matches:
                        if sp not in prof['subpaths'] and len(prof['subpaths']) < 20:
                            prof['subpaths'].append(sp)

                    literal_matches = re.findall(r'literal\s+"([^"]+)"', stripped)
                    for lm in literal_matches:
                        if lm not in prof['file_paths'] and len(prof['file_paths']) < 20:
                            prof['file_paths'].append(lm)

                    # Count operations
                    for cat_name, cat_data in SBPL_OPERATIONS.items():
                        for op_name in cat_data['operations']:
                            if op_name in stripped:
                                prof['operations'][cat_name] += 1

                # Security findings for notable profiles
                if prof['allows_dynamic_code'] and prof['name'] != 'application':
                    self.findings.append(('HIGH', 'Dynamic code generation allowed: %s' % prof['name']))
                if not prof['denies_default'] and prof['allow_count'] > 0:
                    self.findings.append(('MEDIUM', 'No deny-default: %s' % prof['name']))

        except (IOError, OSError):
            return None

        return prof

    def _analyze_app_containers(self):
        """Analyze app sandbox containers"""
        containers = []
        container_dir = os.path.expanduser('~/Library/Containers')
        if not os.path.isdir(container_dir):
            return containers

        for container_name in sorted(os.listdir(container_dir))[:30]:
            container_path = os.path.join(container_dir, container_name)
            if not os.path.isdir(container_path):
                continue

            meta_plist = os.path.join(container_path, 'Container.plist')
            container_info = {
                'uuid': container_name,
                'bundle_id': '',
                'path': container_path,
                'has_data': False,
            }

            # Try to read Container.plist for bundle ID
            if os.path.exists(meta_plist):
                try:
                    proc = subprocess.run(
                        ['plutil', '-convert', 'xml1', '-o', '-', meta_plist],
                        capture_output=True, text=True, timeout=5
                    )
                    if proc.returncode == 0:
                        bid_match = re.search(r'<key>MCMMetadataIdentifier</key>\s*<string>([^<]+)</string>', proc.stdout)
                        if bid_match:
                            container_info['bundle_id'] = bid_match.group(1)
                except (FileNotFoundError, subprocess.TimeoutExpired):
                    pass

            # Check if container has actual data
            data_dir = os.path.join(container_path, 'Data')
            if os.path.isdir(data_dir):
                container_info['has_data'] = True

            containers.append(container_info)

        return containers

    def _compute_risk_score(self, profile):
        """Compute security risk score for a profile (0-10)"""
        score = 0
        if not profile.get('denies_default'):
            score += 3
        if profile.get('allows_dynamic_code'):
            score += 3
        if profile.get('allows_exec'):
            score += 2
        if profile.get('allows_network'):
            score += 1
        if profile.get('allows_file_write'):
            score += 1
        return min(score, 10)


def demo():
    """Run sandbox profile analysis"""
    print("macOS Sandbox Profile Decompiler v1.0")
    print("=" * 60)

    analyzer = SandboxProfileAnalyzer()
    result = analyzer.full_analysis()

    # Statistics
    stats = result['profile_stats']
    print("\n  Profile Statistics:")
    print("    System profiles: %d" % stats['total_profiles'])
    print("    Total allow rules: %d" % stats['total_allow_rules'])
    print("    Total deny rules: %d" % stats['total_deny_rules'])
    print("    App containers: %d" % stats['app_containers'])
    print("    High-risk profiles: %d" % stats['high_risk'])
    print("    Unique operation categories: %d" % stats['unique_operations'])

    # Operation coverage
    print("\n  Operation Coverage (across all profiles):")
    op_coverage = dict(result['operation_coverage'])
    for cat_name in sorted(op_coverage.keys(), key=lambda xx: op_coverage[xx], reverse=True):
        cat_meta = SBPL_OPERATIONS.get(cat_name, {})
        mitre_str = ','.join(cat_meta.get('mitre', [])[:2])
        print("    %-20s %5d hits  %s" % (cat_name, op_coverage[cat_name], mitre_str))

    # High-risk profiles
    if result['high_risk_profiles']:
        print("\n  High-Risk Profiles (risk >= 7):")
        for prof in sorted(result['high_risk_profiles'], key=lambda pp: pp['risk_score'], reverse=True)[:15]:
            flags = []
            if prof.get('allows_dynamic_code'):
                flags.append('DYN-CODE')
            if prof.get('allows_exec'):
                flags.append('EXEC')
            if prof.get('allows_network'):
                flags.append('NET')
            if not prof.get('denies_default'):
                flags.append('NO-DENY')
            flag_str = ' '.join(flags)
            print("    [%d/10] %-35s %4d LOC  %3d allow  %3d deny  %s" % (
                prof['risk_score'], prof['name'][:35], prof['lines'],
                prof['allow_count'], prof['deny_count'], flag_str
            ))

    # Notable profiles (most restrictive)
    print("\n  Most Restrictive Profiles (deny-default, minimal allows):")
    restrictive = [pp for pp in result['system_profiles']
                   if pp.get('denies_default') and pp['allow_count'] < 15]
    for prof in sorted(restrictive, key=lambda pp: pp['allow_count'])[:10]:
        print("    %-35s %3d allow  %3d deny  %4d LOC" % (
            prof['name'][:35], prof['allow_count'], prof['deny_count'], prof['lines']
        ))

    # App containers
    if result['app_containers']:
        print("\n  App Sandbox Containers (%d):" % stats['app_containers'])
        named = [cc for cc in result['app_containers'] if cc.get('bundle_id')]
        unnamed = len(result['app_containers']) - len(named)
        for container in named[:15]:
            data_tag = 'DATA' if container.get('has_data') else '----'
            print("    [%s] %s" % (data_tag, container['bundle_id']))
        if unnamed:
            print("    ... +%d containers without identified bundle ID" % unnamed)

    # Sample profile deep-dive (blastdoor = iMessage)
    for prof in result['system_profiles']:
        if prof['name'] == 'blastdoor':
            print("\n  Deep Dive: blastdoor.sb (iMessage zero-click defense)")
            print("    Lines: %d" % prof['lines'])
            print("    Allow rules: %d" % prof['allow_count'])
            print("    Deny rules: %d" % prof['deny_count'])
            print("    Deny default: %s" % prof['denies_default'])
            print("    Dynamic code: %s" % prof['allows_dynamic_code'])
            print("    Network: %s" % prof['allows_network'])
            print("    Exec: %s" % prof['allows_exec'])
            if prof['imports']:
                print("    Imports: %s" % ', '.join(prof['imports']))
            if prof['mach_services']:
                print("    Mach services (%d): %s" % (len(prof['mach_services']), ', '.join(prof['mach_services'][:5])))
            break

    # Findings
    if result['findings']:
        print("\n  Security Findings (%d):" % len(result['findings']))
        for sev, msg in result['findings'][:20]:
            print("    [%s] %s" % (sev, msg))

    print("\nSandbox profile decompiler ready")


demo()

