#!/usr/bin/env python3
"""macOS CoreTrust Certificate Chain Validator"""
import os, subprocess, re
from collections import defaultdict

# Known problematic CAs (removed from major trust stores)
PROBLEMATIC_CAS = {
    'DigiNotar': {'status': 'REVOKED', 'reason': 'Compromised 2011 — fraudulent Google certs'},
    'Symantec': {'status': 'DISTRUSTED', 'reason': 'Mass mis-issuance, distrust 2018'},
    'WoSign': {'status': 'DISTRUSTED', 'reason': 'Backdating SHA-1 certs, distrust 2016'},
    'StartCom': {'status': 'DISTRUSTED', 'reason': 'WoSign subsidiary, distrust 2016'},
    'CNNIC': {'status': 'REMOVED', 'reason': 'Unauthorized Google cert via MCS Holdings'},
    'TurkTrust': {'status': 'REMOVED', 'reason': 'Mis-issued intermediate CA certs 2013'},
    'ANSSI': {'status': 'CONSTRAINED', 'reason': 'Unauthorized Google cert 2013'},
    'India CCA': {'status': 'CONSTRAINED', 'reason': 'Unauthorized Google certs via NIC'},
}

# Apple root certificate categories
APPLE_ROOT_CATEGORIES = {
    'platform': ['Apple Platform'],
    'code_signing': ['Code Signing'],
    'tls': ['TLS'],
    'developer': ['Developer'],
    'multipurpose': ['Multipurpose'],
    'bootstrap': ['Bootstrap'],
    'legacy': ['Apple Root CA', 'Apple Root Certificate Authority'],
}

# Keychain locations
KEYCHAINS = {
    'system_roots': '/System/Library/Keychains/SystemRootCertificates.keychain',
    'system': '/Library/Keychains/System.keychain',
    'login': os.path.expanduser('~/Library/Keychains/login.keychain-db'),
}


class CoreTrustAnalyzer:
    """Analyze CoreTrust certificate chain and trust store"""

    def __init__(self):
        self.findings = []

    def full_analysis(self):
        """Run complete CoreTrust analysis"""
        result = {
            'coretrust_kext': self._check_coretrust_kext(),
            'root_certificates': self._analyze_root_store(),
            'apple_roots': [],
            'trust_settings': self._check_trust_settings(),
            'admin_trust': self._check_admin_trust(),
            'problematic_cas': [],
            'certificate_categories': defaultdict(int),
            'stats': {},
        }

        # Categorize Apple roots
        for cert in result['root_certificates']:
            cert_name = cert.get('label', '')
            # Check if Apple root
            if 'Apple' in cert_name:
                result['apple_roots'].append(cert)
                # Sub-categorize
                for cat_name, patterns in APPLE_ROOT_CATEGORIES.items():
                    for pattern in patterns:
                        if pattern in cert_name:
                            result['certificate_categories']['apple_' + cat_name] += 1
                            break
            else:
                result['certificate_categories']['third_party'] += 1

            # Check for problematic CAs
            for ca_name, ca_info in PROBLEMATIC_CAS.items():
                if ca_name.lower() in cert_name.lower():
                    result['problematic_cas'].append({
                        'cert_name': cert_name,
                        'ca_name': ca_name,
                        'status': ca_info['status'],
                        'reason': ca_info['reason'],
                    })
                    self.findings.append(('CRITICAL', 'Problematic CA in trust store: %s (%s)' % (cert_name, ca_info['status'])))

        # Check for key security properties
        ecc_count = sum(1 for cc in result['root_certificates'] if 'ECC' in cc.get('label', '') or 'ECDSA' in cc.get('label', ''))
        rsa_count = len(result['root_certificates']) - ecc_count

        result['stats'] = {
            'total_root_certs': len(result['root_certificates']),
            'apple_roots': len(result['apple_roots']),
            'third_party_roots': len(result['root_certificates']) - len(result['apple_roots']),
            'ecc_certs': ecc_count,
            'rsa_certs': rsa_count,
            'problematic_cas': len(result['problematic_cas']),
            'user_trust_overrides': len(result['trust_settings']),
            'admin_trust_overrides': len(result['admin_trust']),
        }

        result['findings'] = self.findings[:]
        return result

    def _check_coretrust_kext(self):
        """Check CoreTrust kernel extension status"""
        info = {
            'loaded': False,
            'version': '',
            'dependencies': [],
            'related_kexts': [],
        }

        try:
            proc = subprocess.run(['kextstat'], capture_output=True, text=True, timeout=10)
            for line in proc.stdout.split('\n'):
                if 'CoreTrust' in line:
                    info['loaded'] = True
                    ver_match = re.search(r'\(([^)]+)\)', line)
                    if ver_match:
                        info['version'] = ver_match.group(1)
                    # Parse dependencies
                    dep_match = re.search(r'<(.+)>', line)
                    if dep_match:
                        info['dependencies'] = dep_match.group(1).split()
                elif any(kk in line for kk in ['AppleImage4', 'corecrypto', 'AppleMobileFileIntegrity']):
                    kext_name = ''
                    name_match = re.search(r'com\.\S+', line)
                    if name_match:
                        kext_name = name_match.group()
                    ver_match = re.search(r'\(([^)]+)\)', line)
                    ver = ver_match.group(1) if ver_match else ''
                    info['related_kexts'].append({'name': kext_name, 'version': ver})
        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass

        return info

    def _analyze_root_store(self):
        """Analyze system root certificate store"""
        certs = []
        keychain_path = KEYCHAINS['system_roots']

        try:
            proc = subprocess.run(
                ['security', 'find-certificate', '-a', '-Z', keychain_path],
                capture_output=True, text=True, timeout=30
            )

            current_cert = {}
            for line in proc.stdout.split('\n'):
                if line.startswith('SHA-1 hash:'):
                    if current_cert.get('sha1'):
                        certs.append(current_cert)
                    current_cert = {'sha1': line.split(':')[1].strip()}
                elif '"labl"' in line:
                    label_match = re.search(r'"labl"<blob>="([^"]*)"', line)
                    if label_match:
                        current_cert['label'] = label_match.group(1)
                elif '"snbr"' in line:
                    serial_match = re.search(r'"snbr"<blob>=0x([A-F0-9]+)', line)
                    if serial_match:
                        current_cert['serial'] = serial_match.group(1)

            if current_cert.get('sha1'):
                certs.append(current_cert)

        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass

        return certs

    def _check_trust_settings(self):
        """Check user trust settings overrides"""
        settings = []
        try:
            proc = subprocess.run(
                ['security', 'dump-trust-settings'],
                capture_output=True, text=True, timeout=10
            )
            current_cert = None
            for line in proc.stdout.split('\n'):
                if line.startswith('Cert'):
                    cert_match = re.search(r'Cert \d+: (.+)', line)
                    if cert_match:
                        current_cert = {'name': cert_match.group(1).strip(), 'domain': 'user', 'settings': []}
                elif 'Policy OID' in line and current_cert:
                    policy = line.split(':')[1].strip() if ':' in line else ''
                    current_cert['settings'].append(policy)
                elif 'Result Type' in line and current_cert:
                    result_type = line.split(':')[1].strip() if ':' in line else ''
                    current_cert['result_type'] = result_type
                    settings.append(current_cert)
                    current_cert = None
        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass

        if settings:
            for ss in settings:
                self.findings.append(('INFO', 'User trust override: %s' % ss['name']))

        return settings

    def _check_admin_trust(self):
        """Check admin trust settings"""
        settings = []
        try:
            proc = subprocess.run(
                ['security', 'dump-trust-settings', '-d'],
                capture_output=True, text=True, timeout=10
            )
            current_cert = None
            for line in proc.stdout.split('\n'):
                if line.startswith('Cert'):
                    cert_match = re.search(r'Cert \d+: (.+)', line)
                    if cert_match:
                        current_cert = {'name': cert_match.group(1).strip(), 'domain': 'admin'}
                        settings.append(current_cert)
                        current_cert = None
        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass

        if settings:
            for ss in settings:
                self.findings.append(('MEDIUM', 'Admin trust override: %s' % ss['name']))

        return settings


def demo():
    """Run CoreTrust analysis"""
    print("macOS CoreTrust Certificate Chain Validator v1.0")
    print("=" * 60)

    analyzer = CoreTrustAnalyzer()
    result = analyzer.full_analysis()

    # CoreTrust kext
    ct = result['coretrust_kext']
    print("\n  CoreTrust Kext: %s (v%s)" % ('LOADED' if ct['loaded'] else 'NOT LOADED', ct['version']))
    if ct['related_kexts']:
        print("  Related Security Kexts:")
        for kext in ct['related_kexts']:
            print("    %s v%s" % (kext['name'], kext['version']))

    # Statistics
    stats = result['stats']
    print("\n  Certificate Store Statistics:")
    print("    Total root certificates: %d" % stats['total_root_certs'])
    print("    Apple roots: %d" % stats['apple_roots'])
    print("    Third-party roots: %d" % stats['third_party_roots'])
    print("    ECC certificates: %d" % stats['ecc_certs'])
    print("    RSA certificates: %d" % stats['rsa_certs'])
    print("    Problematic CAs: %d" % stats['problematic_cas'])
    print("    User trust overrides: %d" % stats['user_trust_overrides'])
    print("    Admin trust overrides: %d" % stats['admin_trust_overrides'])

    # Certificate categories
    print("\n  Certificate Categories:")
    for cat_name, count in sorted(result['certificate_categories'].items()):
        print("    %-25s %d" % (cat_name, count))

    # Apple roots
    print("\n  Apple Root Certificates (%d):" % len(result['apple_roots']))
    for cert in sorted(result['apple_roots'], key=lambda cc: cc.get('label', '')):
        crypto = 'ECC' if 'ECC' in cert.get('label', '') else 'RSA'
        gen = ''
        gen_match = re.search(r'G(\d)', cert.get('label', ''))
        if gen_match:
            gen = 'Gen%s' % gen_match.group(1)
        print("    [%s] %-5s %s" % (crypto, gen, cert.get('label', '')))

    # Third-party roots (sample)
    third_party = [cc for cc in result['root_certificates'] if 'Apple' not in cc.get('label', '')]
    if third_party:
        print("\n  Third-Party Root CAs (%d, showing top 20):" % len(third_party))
        for cert in sorted(third_party, key=lambda cc: cc.get('label', ''))[:20]:
            sha1_short = cert.get('sha1', '')[:16]
            print("    %-55s %s" % (cert.get('label', '')[:55], sha1_short))

    # Trust overrides
    if result['trust_settings'] or result['admin_trust']:
        print("\n  Trust Overrides:")
        for ts in result['trust_settings']:
            print("    [USER]  %s" % ts['name'])
        for ts in result['admin_trust']:
            print("    [ADMIN] %s" % ts['name'])

    # Problematic CAs
    if result['problematic_cas']:
        print("\n  PROBLEMATIC CAs FOUND:")
        for ca in result['problematic_cas']:
            print("    [%s] %s — %s" % (ca['status'], ca['cert_name'], ca['reason']))

    # Findings
    if result['findings']:
        print("\n  Security Findings (%d):" % len(result['findings']))
        for sev, msg in result['findings'][:15]:
            print("    [%s] %s" % (sev, msg))

    print("\nCoreTrust validator ready")


demo()

