"""macOS System Extension + Kext Analyzer"""
import os, subprocess, re
from collections import defaultdict

# Kext categories for security analysis
KEXT_CATEGORIES = {
    'security': {
        'patterns': ['AppleMobileFileIntegrity', 'CoreTrust', 'AppleImage4', 'sandbox', 'quarantine', 'AppleSystemPolicy', 'FairPlayIOKit', 'AppleCredentialManager'],
        'desc': 'Security enforcement kexts',
