# System extension categories
SYSEXT_CATEGORIES = {
    'network_extension': 'content-filter, DNS proxy, packet tunnel, app proxy',
    'endpoint_security': 'ES client — process, file, IPC monitoring',
    'driver_extension': 'DriverKit — userspace hardware driver',
}


class SystemExtKextAnalyzer:
    """Analyze system extensions and kernel extensions"""

    def __init__(self):
        self.findings = []

    def full_analysis(self):
        """Run complete system extension + kext analysis"""
        result = {
            'system_extensions': self._enumerate_system_extensions(),
            'kexts': self._enumerate_kexts(),
            'kext_categories': defaultdict(list),
            'third_party_kexts': [],
            'deprecated_kexts': [],
            'stats': {},
        }

        # Categorize kexts
        for kext in result['kexts']:
            kext_name = kext.get('name', '')
            categorized = False
            for cat_name, cat_data in KEXT_CATEGORIES.items():
                for pattern in cat_data['patterns']:
                    if pattern.lower() in kext_name.lower():
                        result['kext_categories'][cat_name].append(kext)
                        categorized = True
                        break
                if categorized:
                    break
            if not categorized:
                result['kext_categories']['other'].append(kext)

            # Check for third-party kexts (non-Apple)
            if not kext_name.startswith('com.apple.'):
                result['third_party_kexts'].append(kext)
                self.findings.append(('MEDIUM', 'Third-party kext: %s' % kext_name))

        # Check for deprecated/known-vulnerable patterns
        for kext in result['kexts']:
            kext_name = kext.get('name', '')
            if 'kpi.unsupported' in kext_name:
                self.findings.append(('INFO', 'Unsupported KPI loaded: %s' % kext_name))
            if kext.get('refs', 0) == 0 and kext.get('address', '0') != '0':
                # Loaded but no references — potentially orphaned
                pass

        # Analyze dependency depth
        max_deps = 0
        most_depended = None
        for kext in result['kexts']:
            refs = kext.get('refs', 0)
            if refs > max_deps:
                max_deps = refs
                most_depended = kext

        # Statistics
        total_kexts = len(result['kexts'])
        apple_kexts = sum(1 for kk in result['kexts'] if kk.get('name', '').startswith('com.apple.'))
        total_wired = sum(kk.get('wired', 0) for kk in result['kexts'])

        result['stats'] = {
            'total_kexts': total_kexts,
            'apple_kexts': apple_kexts,
            'third_party_kexts': len(result['third_party_kexts']),
            'system_extensions': len(result['system_extensions']),
            'kext_categories': len(result['kext_categories']),
            'total_wired_memory': total_wired,
            'max_dependency_refs': max_deps,
            'most_depended_kext': most_depended['name'] if most_depended else '',
        }

        result['findings'] = self.findings[:]
        return result

    def _enumerate_system_extensions(self):
        """Enumerate system extensions"""
        extensions = []
        try:
            proc = subprocess.run(
                ['systemextensionsctl', 'list'],
                capture_output=True, text=True, timeout=10
            )
            output = proc.stdout + proc.stderr
            current_category = ''

            for line in output.split('\n'):
                if 'com.apple.system_extension.' in line:
                    cat_match = re.search(r'com\.apple\.system_extension\.(\w+)', line)
                    if cat_match:
                        current_category = cat_match.group(1)
                    continue

                # Parse extension entries
                ext_match = re.search(r'([*\s])\s+([*\s])\s+(\w+)\s+(\S+)\s+\(([^)]+)\)\s+(.+?)\s+\[([^\]]+)\]', line)
                if ext_match:
                    ext_info = {
                        'enabled': ext_match.group(1).strip() == '*',
                        'active': ext_match.group(2).strip() == '*',
                        'team_id': ext_match.group(3),
                        'bundle_id': ext_match.group(4),
                        'version': ext_match.group(5),
                        'name': ext_match.group(6).strip(),
                        'state': ext_match.group(7),
                        'category': current_category,
                    }

                    # Get entitlements from disk
                    ext_path = self._find_sysext_path(ext_info['bundle_id'])
                    if ext_path:
                        ext_info['path'] = ext_path
                        ext_info['codesigned'] = self._check_codesign(ext_path)
                        ext_info['frameworks'] = self._get_frameworks(ext_path)

                    extensions.append(ext_info)

        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass

        return extensions

    def _find_sysext_path(self, bundle_id):
        """Find system extension on disk"""
        sysext_dir = '/Library/SystemExtensions'
        if not os.path.isdir(sysext_dir):
            return None
        for uuid_dir in os.listdir(sysext_dir):
            full_path = os.path.join(sysext_dir, uuid_dir)
            if not os.path.isdir(full_path):
                continue
            for ext_name in os.listdir(full_path):
                if ext_name.endswith('.systemextension') and bundle_id in ext_name:
                    return os.path.join(full_path, ext_name)
        return None

    def _check_codesign(self, path):
        """Quick codesign check"""
        try:
            proc = subprocess.run(['codesign', '-v', path], capture_output=True, text=True, timeout=5)
            return proc.returncode == 0
        except (FileNotFoundError, subprocess.TimeoutExpired):
            return False

    def _get_frameworks(self, path):
        """Get linked frameworks"""
        frameworks = []
        macos_dir = os.path.join(path, 'Contents', 'MacOS')
        if os.path.isdir(macos_dir):
            for binary_name in os.listdir(macos_dir):
                try:
                    proc = subprocess.run(
                        ['otool', '-L', os.path.join(macos_dir, binary_name)],
                        capture_output=True, text=True, timeout=5
                    )
                    for line in proc.stdout.split('\n'):
                        fw_match = re.search(r'/([^/]+\.framework)', line)
                        if fw_match:
                            fw_name = fw_match.group(1).replace('.framework', '')
                            if fw_name not in frameworks:
                                frameworks.append(fw_name)
                except (FileNotFoundError, subprocess.TimeoutExpired):
                    pass
                break
        return frameworks

    def _enumerate_kexts(self):
        """Enumerate loaded kernel extensions"""
        kexts = []
        try:
            proc = subprocess.run(['kextstat'], capture_output=True, text=True, timeout=15)

            for line in proc.stdout.split('\n'):
                if not line.strip() or 'Index' in line or 'Executing' in line or 'No variant' in line:
                    continue

                parts = line.split()
                if len(parts) >= 6:
                    kext_info = {
                        'index': int(parts[0]) if parts[0].isdigit() else 0,
                        'refs': int(parts[1]) if parts[1].isdigit() else 0,
                        'address': parts[2],
                        'size': int(parts[3], 16) if parts[3] != '0' else 0,
                        'wired': int(parts[4], 16) if parts[4] != '0' else 0,
                        'name': parts[5] if len(parts) > 5 else '',
                        'version': '',
                        'deps': [],
                    }

                    # Extract version
                    ver_match = re.search(r'\(([^)]+)\)', line)
                    if ver_match:
                        kext_info['version'] = ver_match.group(1)

                    # Extract dependencies
                    dep_match = re.search(r'<([^>]+)>', line)
                    if dep_match:
                        kext_info['deps'] = dep_match.group(1).split()

                    kexts.append(kext_info)

        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass

        return kexts


def demo():
    """Run system extension + kext analysis"""
    print("macOS System Extension + Kext Analyzer v1.0")
    print("=" * 60)

    analyzer = SystemExtKextAnalyzer()
    result = analyzer.full_analysis()

    # Statistics
    stats = result['stats']
    print("\n  Statistics:")
    print("    Loaded kexts: %d" % stats['total_kexts'])
    print("    Apple kexts: %d" % stats['apple_kexts'])
