    print("    Total wired memory: %s" % ('%d KB' % (stats['total_wired_memory'] // 1024)))
    print("    Most depended kext: %s (%d refs)" % (stats['most_depended_kext'], stats['max_dependency_refs']))

    # System extensions
    if result['system_extensions']:
        print("\n  System Extensions (%d):" % stats['system_extensions'])
        for ext in result['system_extensions']:
            status = 'ACTIVE' if ext.get('active') else 'INACTIVE'
            signed = 'Signed' if ext.get('codesigned') else 'UNSIGNED'
            cat = ext.get('category', 'unknown')
            print("    [%s] [%s] %-30s %s" % (status, signed, ext['name'][:30], ext['bundle_id']))
            print("           Category: %s | Team: %s | Version: %s | State: %s" % (
                cat, ext['team_id'], ext['version'], ext['state']
            ))
            if ext.get('frameworks'):
                print("           Frameworks: %s" % ', '.join(ext['frameworks'][:6]))

    # Kext categories
    print("\n  Kext Categories:")
    for cat_name in sorted(result['kext_categories'].keys()):
        cat_kexts = result['kext_categories'][cat_name]
        cat_meta = KEXT_CATEGORIES.get(cat_name, {})
        desc = cat_meta.get('desc', '') if cat_meta else ''
        print("    %-20s %3d kexts  %s" % (cat_name, len(cat_kexts), desc))

    # Security kexts detail
    sec_kexts = result['kext_categories'].get('security', [])
    if sec_kexts:
        print("\n  Security Kexts (%d):" % len(sec_kexts))
        for kext in sorted(sec_kexts, key=lambda kk: kk.get('refs', 0), reverse=True):
            size_kb = kext.get('size', 0) // 1024
