                kext['name'][:50], kext['version'], size_kb,
                kext['refs'], len(kext['deps'])
            ))

    # Crypto kexts
    crypto_kexts = result['kext_categories'].get('crypto', [])
    if crypto_kexts:
        print("\n  Crypto Kexts (%d):" % len(crypto_kexts))
        for kext in crypto_kexts:
            size_kb = kext.get('size', 0) // 1024
            print("    %-50s v%-8s %4d KB" % (kext['name'][:50], kext['version'], size_kb))

    # Top kexts by dependency count
    print("\n  Most Referenced Kexts (dependency hubs):")
    top_refs = sorted(result['kexts'], key=lambda kk: kk.get('refs', 0), reverse=True)[:10]
    for kext in top_refs:
        print("    %3d refs  %-50s v%s" % (kext['refs'], kext['name'][:50], kext['version']))

    # Top kexts by size
    print("\n  Largest Kexts (by wired memory):")
    top_size = sorted(result['kexts'], key=lambda kk: kk.get('wired', 0), reverse=True)[:10]
    for kext in top_size:
        size_kb = kext.get('wired', 0) // 1024
        if size_kb > 0:
