import os, subprocess, plistlib, sqlite3, re, json
from collections import defaultdict
from pathlib import Path

class EntitlementKillChainEngine:
    """Cross-reference ALL macOS security data to find multi-step privilege escalation chains"""

    # TCC service privilege levels
    TCC_PRIVILEGES = {
        'kTCCServiceCamera': 7, 'kTCCServiceMicrophone': 7,
        'kTCCServiceScreenCapture': 8, 'kTCCServiceAccessibility': 9,
        'kTCCServiceSystemPolicyAllFiles': 10, 'kTCCServiceSystemPolicySysAdminFiles': 10,
        'kTCCServiceAppleEvents': 5, 'kTCCServiceAddressBook': 4,
        'kTCCServiceCalendar': 4, 'kTCCServicePhotos': 5,
        'kTCCServiceMediaLibrary': 4, 'kTCCServiceRemovableVolume': 3,
        'kTCCServiceListenEvent': 8, 'kTCCServicePostEvent': 8,
    }

    # Dangerous entitlements
    DANGEROUS_ENTITLEMENTS = {
        'com.apple.private.tcc.allow': 9,
        'com.apple.private.tcc.manager': 10,
        'com.apple.rootless.install': 10,
        'com.apple.rootless.install.heritable': 10,
        'com.apple.security.cs.disable-library-validation': 7,
        'com.apple.security.cs.allow-unsigned-executable-memory': 8,
        'com.apple.security.cs.allow-dyld-environment-variables': 7,
        'com.apple.security.cs.debugger': 8,
        'com.apple.private.security.no-sandbox': 9,
        'com.apple.security.temporary-exception.mach-lookup.global-name': 6,
        'task_for_pid-allow': 10,
        'com.apple.private.amfi.can-load-cdhash': 9,
        'com.apple.private.kernel.override-cpumon': 5,
        'com.apple.security.device.audio-input': 6,
        'com.apple.security.device.camera': 6,
    }

    # IOKit classes with known CVEs
    IOKIT_CVE_CLASSES = {
        'IOSurfaceRootUserClient': ['CVE-2021-30807', 'CVE-2023-38606'],
        'AGXCommandQueue': ['CVE-2023-32434'],
        'IOHIDEventServiceUserClient': ['CVE-2016-4654'],  # Pegasus
        'AppleAVEDriver': ['CVE-2022-32893'],
        'IOMobileFramebufferUserClient': ['CVE-2021-30883'],
        'AppleKeyStoreUserClient': ['CVE-2020-9839'],
    }

    def __init__(self):
        self.findings = []
        self.chains = []
        self.tcc_grants = {}      # app -> [services]
        self.app_security = {}    # app -> {hardened_runtime, library_validation, sandbox}
        self.xpc_services = {}    # service -> {entitlements, connection_type}
        self.dylib_hijacks = {}   # app -> [missing_dylibs]
        self.sandbox_access = {}  # profile -> {iokit_classes, mach_services, file_access}
        self.iokit_clients = {}   # class -> {instances, access_level}
        self.amfi_bypass = {}     # binary -> {flags, weaknesses}

    def collect_tcc_grants(self):
        """Query TCC.db for all granted permissions"""
        tcc_paths = [
            os.path.expanduser('~/Library/Application Support/com.apple.TCC/TCC.db'),
            '/Library/Application Support/com.apple.TCC/TCC.db',
        ]
        for tcc_path in tcc_paths:
            if not os.path.exists(tcc_path):
                continue
            try:
                conn = sqlite3.connect('file:%s?mode=ro' % tcc_path, uri=True)
                cursor = conn.execute(
                    "SELECT client, service, auth_value, auth_reason FROM access WHERE auth_value = 2"
                )
                for row in cursor:
                    client, service, auth_val, auth_reason = row
                    if client not in self.tcc_grants:
                        self.tcc_grants[client] = []
                    self.tcc_grants[client].append({
                        'service': service,
                        'privilege': self.TCC_PRIVILEGES.get(service, 3),
                        'db': 'user' if '~' in tcc_path or 'Users' in tcc_path else 'system',
                    })
                conn.close()
            except (sqlite3.OperationalError, sqlite3.DatabaseError):
                pass

    def collect_app_security(self):
        """Check hardened runtime and library validation for apps with TCC grants"""
        apps_to_check = set()
        for client in self.tcc_grants:
            if client.startswith('/'):
                apps_to_check.add(client)
            else:
                # Bundle ID - find the binary
                app_paths = [
                    '/Applications/%s.app' % client.split('.')[-1],
                ]
                for ap in app_paths:
                    if os.path.exists(ap):
                        apps_to_check.add(ap)

        # Also check common app directories
        for app_dir in ['/Applications', os.path.expanduser('~/Applications')]:
            if os.path.isdir(app_dir):
                for item in os.listdir(app_dir):
                    if item.endswith('.app'):
                        apps_to_check.add(os.path.join(app_dir, item))

        for app_path in apps_to_check:
            binary = app_path
            if app_path.endswith('.app'):
                # Find the actual binary inside the .app
                app_name = os.path.basename(app_path).replace('.app', '')
                binary = os.path.join(app_path, 'Contents', 'MacOS', app_name)
                if not os.path.exists(binary):
                    # Try finding any binary
                    macos_dir = os.path.join(app_path, 'Contents', 'MacOS')
                    if os.path.isdir(macos_dir):
                        bins = os.listdir(macos_dir)
                        if bins:
                            binary = os.path.join(macos_dir, bins[0])

            if not os.path.exists(binary):
                continue

            try:
                result = subprocess.run(
                    ['codesign', '-dvv', binary],
                    capture_output=True, text=True, timeout=5
                )
                output = result.stderr  # codesign outputs to stderr

                flags = ''
                for line in output.split('\n'):
                    if line.startswith('CodeDirectory'):
                        flags = line
                    elif 'flags=' in line.lower():
                        flags += ' ' + line

                hardened = 'runtime' in output.lower()
                lib_val = 'library-validation' in output.lower()
                restricted = 'restrict' in output.lower()

                self.app_security[app_path] = {
                    'binary': binary,
                    'hardened_runtime': hardened,
                    'library_validation': lib_val,
                    'restricted': restricted,
                    'injectable': not hardened or not lib_val,
                    'flags': flags.strip(),
                }
            except (subprocess.TimeoutExpired, FileNotFoundError, PermissionError):
                pass

    def collect_dylib_hijacks(self):
        """Find dylib hijack opportunities for injectable apps"""
        for app_path, info in self.app_security.items():
            if not info.get('injectable'):
                continue
            binary = info['binary']
            try:
                result = subprocess.run(
                    ['otool', '-L', binary],
                    capture_output=True, text=True, timeout=10
                )
                hijacks = []
                for line in result.stdout.split('\n')[1:]:
                    line = line.strip()
                    if not line:
                        continue
                    dylib_path = line.split(' (')[0].strip()
                    if dylib_path.startswith('@rpath') or dylib_path.startswith('@loader_path'):
                        hijacks.append({
                            'dylib': dylib_path,
                            'type': 'rpath' if '@rpath' in dylib_path else 'loader_path',
                        })
                    elif not os.path.exists(dylib_path) and dylib_path.startswith('/'):
                        hijacks.append({
                            'dylib': dylib_path,
                            'type': 'missing',
                        })
                if hijacks:
                    self.dylib_hijacks[app_path] = hijacks
            except (subprocess.TimeoutExpired, FileNotFoundError):
                pass

    def collect_xpc_services(self):
        """Enumerate XPC services and their entitlements"""
        xpc_dirs = [
            '/System/Library/XPCServices',
            '/Library/LaunchDaemons',
            '/Library/LaunchAgents',
            os.path.expanduser('~/Library/LaunchAgents'),
        ]

        for xpc_dir in xpc_dirs:
            if not os.path.isdir(xpc_dir):
                continue
            for item in os.listdir(xpc_dir):
                full_path = os.path.join(xpc_dir, item)
                if item.endswith('.xpc'):
                    binary = os.path.join(full_path, 'Contents', 'MacOS', item.replace('.xpc', ''))
                    if not os.path.exists(binary):
                        # Try any binary inside
                        macos = os.path.join(full_path, 'Contents', 'MacOS')
                        if os.path.isdir(macos):
                            bins = os.listdir(macos)
                            if bins:
                                binary = os.path.join(macos, bins[0])
                    if os.path.exists(binary):
                        ents = self._get_entitlements(binary)
                        dangerous = [e for e in ents if e in self.DANGEROUS_ENTITLEMENTS]
                        if dangerous:
                            self.xpc_services[item] = {
                                'binary': binary,
                                'entitlements': ents,
                                'dangerous': dangerous,
                                'max_privilege': max(self.DANGEROUS_ENTITLEMENTS.get(e, 0) for e in dangerous),
                            }
                elif item.endswith('.plist'):
                    try:
                        with open(full_path, 'rb') as f:
                            plist = plistlib.load(f)
                        label = plist.get('Label', item)
                        program = plist.get('Program', '')
                        if not program and 'ProgramArguments' in plist:
                            program = plist['ProgramArguments'][0] if plist['ProgramArguments'] else ''
                        if program and os.path.exists(program):
                            ents = self._get_entitlements(program)
                            dangerous = [e for e in ents if e in self.DANGEROUS_ENTITLEMENTS]
                            if dangerous:
                                self.xpc_services[label] = {
                                    'binary': program,
                                    'entitlements': ents,
                                    'dangerous': dangerous,
                                    'max_privilege': max(self.DANGEROUS_ENTITLEMENTS.get(e, 0) for e in dangerous),
                                }
                    except (plistlib.InvalidFileException, KeyError, PermissionError):
                        pass

    def _get_entitlements(self, binary):
        """Extract entitlements from a binary"""
        try:
            result = subprocess.run(
                ['codesign', '-d', '--entitlements', '-', '--xml', binary],
                capture_output=True, text=True, timeout=5
            )
            if result.stdout:
                # Parse entitlements plist
                ents = []
                for line in result.stdout.split('\n'):
                    line = line.strip()
                    # Look for key tags
                    if '<key>' in line:
                        key = line.replace('<key>', '').replace('</key>', '').strip()
                        ents.append(key)
                return ents
        except (subprocess.TimeoutExpired, FileNotFoundError):
            pass
        return []

    def collect_iokit_surface(self):
        """Enumerate IOKit user client classes accessible"""
        try:
            result = subprocess.run(
                ['ioreg', '-l', '-w', '0'],
                capture_output=True, text=True, timeout=15
            )
            for line in result.stdout.split('\n'):
                if 'UserClient' in line and '<class' in line:
                    match = re.search(r'<class (\w+UserClient)', line)
                    if match:
                        cls = match.group(1)
                        if cls not in self.iokit_clients:
                            self.iokit_clients[cls] = {
                                'instances': 0,
                                'has_cve': cls in self.IOKIT_CVE_CLASSES,
                                'cves': self.IOKIT_CVE_CLASSES.get(cls, []),
                            }
                        self.iokit_clients[cls]['instances'] += 1
        except (subprocess.TimeoutExpired, FileNotFoundError):
            pass

    def build_kill_chains(self):
        """Construct multi-step privilege escalation chains"""
        self.chains = []

        # Chain Type 1: TCC App → Dylib Injection → Elevated Access
        for app, grants in self.tcc_grants.items():
            app_info = None
            for path, info in self.app_security.items():
                if app in path or path in app:
                    app_info = info
                    break

            if app_info and app_info.get('injectable'):
                max_tcc_priv = max(g['privilege'] for g in grants)
                tcc_services = [g['service'] for g in grants]

                hijacks = []
                for path, h in self.dylib_hijacks.items():
                    if app in path or path in app:
                        hijacks = h
                        break

                chain = {
                    'type': 'TCC_INJECTION',
                    'steps': [],
                    'score': 0,
                    'risk': 'CRITICAL' if max_tcc_priv >= 8 else 'HIGH',
                }

                # Step 1: Identify injectable app
                chain['steps'].append({
                    'action': 'TARGET',
                    'detail': '%s (TCC: %s)' % (os.path.basename(app), ', '.join(tcc_services)),
                    'privilege': max_tcc_priv,
                })

                # Step 2: Injection vector
                if hijacks:
                    chain['steps'].append({
                        'action': 'INJECT_DYLIB',
                        'detail': 'Hijack %s (%d candidates)' % (hijacks[0]['dylib'], len(hijacks)),
                        'method': 'dylib_hijack',
                    })
                    chain['score'] += 20
                elif not app_info.get('hardened_runtime'):
                    chain['steps'].append({
                        'action': 'INJECT_DYLD',
