                elif not app_info.get('library_validation'):
                    chain['steps'].append({
                        'action': 'INJECT_DYLIB',
                        'detail': 'Unsigned dylib load (no library validation)',
                        'method': 'unsigned_dylib',
                    })
                    chain['score'] += 15

                # Step 3: What we gain
                chain['steps'].append({
                    'action': 'GAIN_TCC',
                    'detail': 'Inherit TCC grants: %s' % ', '.join(tcc_services),
                    'privilege_gained': max_tcc_priv,
                })
                chain['score'] += max_tcc_priv * 5

                # Step 4: Can we reach IOKit from here?
                for cls, info in self.iokit_clients.items():
                    if info.get('has_cve'):
                        chain['steps'].append({
                            'action': 'REACH_IOKIT',
                            'detail': '%s (%s)' % (cls, ', '.join(info['cves'])),
                            'kernel_access': True,
                        })
                        chain['score'] += 30
                        chain['risk'] = 'CRITICAL'
                        break

                if len(chain['steps']) >= 3:
                    self.chains.append(chain)

        # Chain Type 2: XPC Service → Entitlement Escalation → TCC Bypass
        for svc_name, svc_info in self.xpc_services.items():
