                        'action': 'TCC_BYPASS',
                        'detail': 'TCC manager = full TCC control',
                        'privilege_gained': 10,
                    })
                    chain['score'] += 50

                self.chains.append(chain)

        # Chain Type 3: Dylib Hijack → Process Injection → XPC → Kernel
        for app_path, hijacks in self.dylib_hijacks.items():
            app_info = self.app_security.get(app_path, {})

            # Find XPC services this app might connect to
            app_bundle = os.path.basename(app_path).replace('.app', '')
            related_xpc = [
                (name, info) for name, info in self.xpc_services.items()
                if app_bundle.lower() in name.lower()
            ]

            if related_xpc:
                for xpc_name, xpc_info in related_xpc:
                    chain = {
                        'type': 'DYLIB_XPC_CHAIN',
                        'steps': [
                            {'action': 'HIJACK_DYLIB', 'detail': '%s in %s' % (hijacks[0]['dylib'], app_path)},
                            {'action': 'CONNECT_XPC', 'detail': 'Reach %s' % xpc_name},
                            {'action': 'ESCALATE', 'detail': 'Via %s' % ', '.join(xpc_info['dangerous'][:2])},
                        ],
                        'score': 15 + xpc_info['max_privilege'] * 5,
                        'risk': 'HIGH',
                    }
                    self.chains.append(chain)

        # Sort by score
        self.chains.sort(key=lambda c: c['score'], reverse=True)

    def generate_report(self):
        """Generate findings report"""
        report = {
            'tcc_grants': len(self.tcc_grants),
            'apps_analyzed': len(self.app_security),
            'injectable_apps': sum(1 for a in self.app_security.values() if a.get('injectable')),
            'dylib_hijack_targets': len(self.dylib_hijacks),
            'xpc_services': len(self.xpc_services),
