import os, subprocess, struct, ctypes, stat, re
from collections import defaultdict

class AMFIBypassScanner:
    """Identify binaries that bypass AMFI enforcement on the running system"""

    # Entitlements that weaken AMFI
    AMFI_WEAKENING = {
        'com.apple.security.cs.allow-unsigned-executable-memory': 'JIT/RWX memory',
        'com.apple.security.cs.disable-library-validation': 'No library validation',
        'com.apple.security.cs.allow-dyld-environment-variables': 'DYLD env vars allowed',
        'com.apple.security.cs.debugger': 'Debugger access',
        'com.apple.security.get-task-allow': 'Task port access (debug)',
        'com.apple.security.cs.disable-executable-page-protection': 'No exec page protection',
    }

    # Mach-O code signing flags
    CS_VALID = 0x00000001
    CS_HARD = 0x00000100
    CS_KILL = 0x00000200
    CS_RESTRICT = 0x00000800
    CS_RUNTIME = 0x00010000
    CS_LINKER_SIGNED = 0x00020000

    def __init__(self):
        self.binaries = []
        self.findings = []
        self.amfi_status = {}

    def check_amfi_status(self):
        """Check system-wide AMFI status via sysctl"""
        self.amfi_status = {
            'amfi_enabled': True,
            'sip_enabled': True,
            'developer_mode': False,
            'allow_everything': False,
        }

        # Check SIP status
        try:
            result = subprocess.run(
                ['csrutil', 'status'],
                capture_output=True, text=True, timeout=5
            )
            if 'disabled' in result.stdout.lower():
                self.amfi_status['sip_enabled'] = False
                self.findings.append({
                    'severity': 'CRITICAL',
                    'detail': 'SIP is DISABLED — all AMFI enforcement weakened',
                })
        except (subprocess.TimeoutExpired, FileNotFoundError):
            pass

        # Check sysctl AMFI values
        amfi_sysctls = [
            'security.mac.amfi.developer_mode_status',
            'security.mac.amfi.allow_everything',
        ]
        for sysctl_name in amfi_sysctls:
            try:
                result = subprocess.run(
                    ['sysctl', sysctl_name],
                    capture_output=True, text=True, timeout=5
                )
                if result.returncode == 0:
                    val = result.stdout.strip().split(':')[-1].strip()
                    key = sysctl_name.split('.')[-1]
                    self.amfi_status[key] = val == '1'
                    if val == '1' and key == 'developer_mode_status':
                        self.findings.append({
                            'severity': 'CRITICAL',
                            'detail': 'Developer Mode ENABLED — AMFI enforcement relaxed',
                        })
            except (subprocess.TimeoutExpired, FileNotFoundError):
                pass

    def scan_binaries(self, scan_dirs=None):
        """Scan system binaries for AMFI bypass conditions"""
        if scan_dirs is None:
            scan_dirs = [
                '/usr/bin', '/usr/sbin', '/usr/local/bin',
                '/usr/libexec', '/sbin', '/bin',
            ]

        for scan_dir in scan_dirs:
            if not os.path.isdir(scan_dir):
                continue
            for item in os.listdir(scan_dir):
                full_path = os.path.join(scan_dir, item)
                if not os.path.isfile(full_path):
                    continue
                if os.path.islink(full_path):
                    continue

                # Check if it's a Mach-O binary
                try:
                    with open(full_path, 'rb') as f:
                        magic = f.read(4)
                    if magic not in (b'\xcf\xfa\xed\xfe', b'\xce\xfa\xed\xfe', b'\xca\xfe\xba\xbe'):
                        continue  # Not Mach-O
                except (PermissionError, OSError):
                    continue

                binary_info = self._analyze_binary(full_path)
                if binary_info:
                    self.binaries.append(binary_info)

    def _analyze_binary(self, path):
        """Analyze a single binary for AMFI-related properties"""
        info = {
            'path': path,
            'name': os.path.basename(path),
            'size': 0,
            'suid': False,
            'sgid': False,
            'signed': False,
            'hardened_runtime': False,
            'library_validation': False,
            'restricted': False,
            'kill_flag': False,
            'linker_signed': False,
            'entitlements': [],
            'amfi_weakening': [],
            'has_network': False,
            'has_file_access': False,
            'has_exec': False,
            'bypass_count': 0,
        }

        # File stats
        try:
            st = os.stat(path)
            info['size'] = st.st_size
            info['suid'] = bool(st.st_mode & stat.S_ISUID)
            info['sgid'] = bool(st.st_mode & stat.S_ISGID)
        except OSError:
            return None

        # Code signing analysis
        try:
            result = subprocess.run(
                ['codesign', '-dvv', path],
                capture_output=True, text=True, timeout=5
            )
            output = result.stderr
            info['signed'] = result.returncode == 0

            # Parse flags
            for line in output.split('\n'):
                ll = line.lower()
                if 'flags=' in ll:
                    if 'runtime' in ll:
                        info['hardened_runtime'] = True
                    if 'library-validation' in ll:
                        info['library_validation'] = True
                    if 'restrict' in ll:
                        info['restricted'] = True
                    if 'kill' in ll:
                        info['kill_flag'] = True
                    if 'linker-signed' in ll:
                        info['linker_signed'] = True
        except (subprocess.TimeoutExpired, FileNotFoundError):
            pass

        # Entitlement extraction
        try:
            result = subprocess.run(
                ['codesign', '-d', '--entitlements', '-', path],
                capture_output=True, timeout=5
            )
            ent_output = result.stdout.decode('utf-8', errors='replace')
            for line in ent_output.split('\n'):
                if '<key>' in line:
                    match = re.search(r'<key>(.*?)</key>', line)
                    if match:
                        ent = match.group(1)
                        info['entitlements'].append(ent)
                        if ent in self.AMFI_WEAKENING:
                            info['amfi_weakening'].append((ent, self.AMFI_WEAKENING[ent]))
                            info['bypass_count'] += 1
        except (subprocess.TimeoutExpired, FileNotFoundError):
            pass

        # Check binary capabilities (via otool imports)
        try:
            result = subprocess.run(
                ['nm', '-u', path],
                capture_output=True, text=True, timeout=5
            )
            imports = result.stdout.lower()
            info['has_network'] = any(s in imports for s in ['_socket', '_connect', '_send', '_recv', '_getaddrinfo'])
            info['has_file_access'] = any(s in imports for s in ['_open', '_fopen', '_read', '_write', '_unlink'])
            info['has_exec'] = any(s in imports for s in ['_execv', '_posix_spawn', '_system', '_popen', '_fork'])
        except (subprocess.TimeoutExpired, FileNotFoundError):
            pass

        # Count bypass conditions
        if not info['hardened_runtime']:
            info['bypass_count'] += 1
        if not info['library_validation']:
            info['bypass_count'] += 1
        if info['linker_signed'] and not info['signed']:
            info['bypass_count'] += 1
        if info['suid']:
            info['bypass_count'] += 2  # SUID is extra dangerous

        return info

    def identify_bypasses(self):
        """Identify specific AMFI bypass conditions"""
        for binary in self.binaries:
            # Condition 1: No hardened runtime + interesting capabilities
            if not binary['hardened_runtime'] and (binary['has_network'] or binary['has_exec']):
                severity = 'CRITICAL' if binary['suid'] else 'HIGH'
                suid_str = ' (SUID!)' if binary['suid'] else ''
                self.findings.append({
                    'severity': severity,
                    'binary': binary['path'],
                    'detail': 'No hardened runtime%s: can load arbitrary code via DYLD' % suid_str,
                    'bypass': 'no_hr',
                })

            # Condition 2: JIT entitlement = RWX pages
            for ent, desc in binary['amfi_weakening']:
                if 'unsigned-executable-memory' in ent:
                    self.findings.append({
                        'severity': 'HIGH',
                        'binary': binary['path'],
                        'detail': 'JIT entitlement: can create RWX memory pages (%s)' % desc,
                        'bypass': 'jit',
                    })
                elif 'disable-library-validation' in ent:
                    self.findings.append({
                        'severity': 'HIGH',
                        'binary': binary['path'],
                        'detail': 'Library validation disabled: can load unsigned dylibs',
                        'bypass': 'no_lv',
                    })

            # Condition 3: Linker-signed only (ad-hoc, no Apple signature)
            if binary['linker_signed'] and not binary['signed']:
                self.findings.append({
                    'severity': 'MEDIUM',
                    'binary': binary['path'],
                    'detail': 'Linker-signed only (ad-hoc) — weakest signing level',
                    'bypass': 'linker_signed',
                })

            # Condition 4: get-task-allow = debuggable
            for ent, desc in binary['amfi_weakening']:
                if 'get-task-allow' in ent:
                    self.findings.append({
                        'severity': 'MEDIUM',
                        'binary': binary['path'],
                        'detail': 'get-task-allow: process can be attached to by debugger',
                        'bypass': 'debug',
                    })

    def generate_report(self):
        """Generate AMFI bypass report"""
        report = {
            'amfi_status': self.amfi_status,
            'total_binaries': len(self.binaries),
            'signed': sum(1 for b in self.binaries if b['signed']),
            'hardened_runtime': sum(1 for b in self.binaries if b['hardened_runtime']),
            'library_validation': sum(1 for b in self.binaries if b['library_validation']),
            'suid': sum(1 for b in self.binaries if b['suid']),
            'with_weakening': sum(1 for b in self.binaries if b['amfi_weakening']),
            'with_network': sum(1 for b in self.binaries if b['has_network']),
            'with_exec': sum(1 for b in self.binaries if b['has_exec']),
            'findings': len(self.findings),
        }
        return report

def demo():
    """Run AMFI bypass analysis"""
    print("macOS AMFI Policy Bypass Scanner v1.0")
    print("=" * 60)

    engine = AMFIBypassScanner()

    print("\n[Phase 1] Checking system AMFI status...")
    engine.check_amfi_status()
    for key, val in engine.amfi_status.items():
        status = 'YES' if val else 'NO'
        print("  %-30s %s" % (key, status))

    print("\n[Phase 2] Scanning system binaries...")
    engine.scan_binaries()
    print("  Binaries analyzed: %d" % len(engine.binaries))

    print("\n[Phase 3] Identifying AMFI bypasses...")
    engine.identify_bypasses()

    report = engine.generate_report()
    print("\n" + "=" * 60)
    print("AMFI BYPASS SCAN RESULTS")
    print("=" * 60)
    print("  Total binaries: %d" % report['total_binaries'])
    print("  Properly signed: %d (%.0f%%)" % (report['signed'], 100*report['signed']/max(report['total_binaries'],1)))
    print("  Hardened runtime: %d (%.0f%%)" % (report['hardened_runtime'], 100*report['hardened_runtime']/max(report['total_binaries'],1)))
    print("  Library validation: %d (%.0f%%)" % (report['library_validation'], 100*report['library_validation']/max(report['total_binaries'],1)))
    print("  SUID binaries: %d" % report['suid'])
    print("  With AMFI-weakening entitlements: %d" % report['with_weakening'])
    print("  With network access: %d" % report['with_network'])
    print("  With exec capability: %d" % report['with_exec'])
    print("  Security findings: %d" % report['findings'])

    # Top bypass binaries
    bypass_sorted = sorted(engine.binaries, key=lambda b: b['bypass_count'], reverse=True)
    top_bypass = [b for b in bypass_sorted if b['bypass_count'] > 0][:20]
    if top_bypass:
        print("\nTop AMFI Bypass Binaries (by bypass count):")
        print("-" * 60)
        for b in top_bypass:
            hr = 'HR' if b['hardened_runtime'] else 'NO-HR'
            lv = 'LV' if b['library_validation'] else 'NO-LV'
            suid = ' SUID' if b['suid'] else ''
            caps = []
            if b['has_network']: caps.append('NET')
            if b['has_exec']: caps.append('EXEC')
            if b['has_file_access']: caps.append('FILE')
            weakening = ', '.join(desc for _, desc in b['amfi_weakening'][:2])
            print("  [%d] %-25s [%s, %s%s] %s %s" % (
                b['bypass_count'], b['name'][:25], hr, lv, suid,
                '+'.join(caps) if caps else '', weakening))

    # SUID binaries detail
    suid_bins = [b for b in engine.binaries if b['suid']]
    if suid_bins:
        print("\nSUID Binaries (%d):" % len(suid_bins))
        for b in suid_bins:
            hr = 'HR' if b['hardened_runtime'] else 'NO-HR'
            print("  %-30s [%s] %s" % (b['name'], hr, b['path']))

    # Findings summary
    by_severity = defaultdict(int)
    by_bypass = defaultdict(int)
    for f in engine.findings:
        by_severity[f['severity']] += 1
        if 'bypass' in f:
            by_bypass[f['bypass']] += 1

    if by_severity:
        print("\nFindings by Severity:")
        for sev in ['CRITICAL', 'HIGH', 'MEDIUM', 'LOW']:
            if sev in by_severity:
                print("  %-10s %d" % (sev, by_severity[sev]))

    if by_bypass:
        print("\nBypass Types:")
        for bp, count in sorted(by_bypass.items(), key=lambda x: x[1], reverse=True):
            print("  %-20s %d" % (bp, count))

    print("\nAMFI bypass scan complete")

demo()

