        'kTCCServiceScreenCapture': ('Screen Recording', 8, 'Capture screen content'),
        'kTCCServiceCamera': ('Camera', 7, 'Capture video'),
        'kTCCServiceMicrophone': ('Microphone', 7, 'Capture audio'),
        'kTCCServiceSystemPolicyDesktopFolder': ('Desktop', 5, 'Desktop file access'),
        'kTCCServiceSystemPolicyDocumentsFolder': ('Documents', 5, 'Documents access'),
        'kTCCServiceSystemPolicyDownloadsFolder': ('Downloads', 5, 'Downloads access'),
        'kTCCServiceAppleEvents': ('Apple Events', 5, 'Inter-app automation'),
        'kTCCServicePostEvent': ('Input Monitoring', 8, 'Keylogging capability'),
        'kTCCServiceListenEvent': ('Input Monitoring', 8, 'Keylogging capability'),
        'kTCCServiceDeveloperTool': ('Developer Tool', 6, 'Debug processes'),
    }

    def __init__(self):
        self.chains = []
        self.findings = []
        self.tcc_apps = {}
        self.injectable_apps = {}
        self.iokit_surface = {}

    def collect_tcc_apps(self):
        """Get all apps with TCC grants"""
        tcc_paths = [
            os.path.expanduser('~/Library/Application Support/com.apple.TCC/TCC.db'),
            '/Library/Application Support/com.apple.TCC/TCC.db',
        ]
        for tcc_path in tcc_paths:
            if not os.path.exists(tcc_path):
                continue
            try:
                conn = sqlite3.connect('file:%s?mode=ro' % tcc_path, uri=True)
                cursor = conn.execute(
                    "SELECT client, service, auth_value FROM access WHERE auth_value = 2"
                )
                for client, service, auth_val in cursor:
                    if client not in self.tcc_apps:
                        self.tcc_apps[client] = {
                            'services': [],
                            'max_impact': 0,
                            'db': 'user' if 'Users' in tcc_path else 'system',
                        }
                    impact_info = self.TCC_IMPACT.get(service, (service, 3, ''))
                    self.tcc_apps[client]['services'].append({
                        'service': service,
                        'name': impact_info[0],
                        'impact': impact_info[1],
                        'capability': impact_info[2],
                    })
                    self.tcc_apps[client]['max_impact'] = max(
                        self.tcc_apps[client]['max_impact'], impact_info[1]
                    )
                conn.close()
            except (sqlite3.OperationalError, sqlite3.DatabaseError):
                pass

    def find_injectable_apps(self):
        """Check which TCC apps are injectable via dylib injection"""
        for client, info in self.tcc_apps.items():
            binary = self._resolve_binary(client)
            if not binary or not os.path.exists(binary):
                continue

            # Check code signing
            security = self._check_security(binary)

            if security['injectable']:
                self.injectable_apps[client] = {
                    'binary': binary,
                    'security': security,
                    'tcc_services': info['services'],
                    'max_impact': info['max_impact'],
                    'injection_method': self._determine_injection_method(security),
                }

    def _resolve_binary(self, client):
        """Resolve a TCC client identifier to a binary path"""
        if client.startswith('/'):
            return client

        # Try common app locations
        app_name = client.split('.')[-1]
        candidates = [
            '/Applications/%s.app/Contents/MacOS/%s' % (app_name, app_name),
            '/Applications/%s.app/Contents/MacOS/%s' % (app_name.capitalize(), app_name.capitalize()),
        ]

        # Search /Applications for matching bundle ID
        if os.path.isdir('/Applications'):
            for item in os.listdir('/Applications'):
                if item.endswith('.app'):
                    info_plist = '/Applications/%s/Contents/Info.plist' % item
                    if os.path.exists(info_plist):
                        try:
                            import plistlib
                            with open(info_plist, 'rb') as f:
                                plist = plistlib.load(f)
                            if plist.get('CFBundleIdentifier') == client:
                                exe = plist.get('CFBundleExecutable', '')
                                if exe:
                                    return '/Applications/%s/Contents/MacOS/%s' % (item, exe)
                        except Exception:
                            pass

        for c in candidates:
            if os.path.exists(c):
                return c
        return None

    def _check_security(self, binary):
        """Check binary security posture"""
        result = {
            'hardened_runtime': False,
            'library_validation': False,
            'restricted': False,
            'suid': False,
            'injectable': False,
        }

        try:
            st = os.stat(binary)
            result['suid'] = bool(st.st_mode & stat.S_ISUID)
        except OSError:
            pass

        try:
            r = subprocess.run(['codesign', '-dvv', binary],
                               capture_output=True, text=True, timeout=5)
            output = r.stderr
            result['hardened_runtime'] = 'runtime' in output.lower()
            result['library_validation'] = 'library-validation' in output.lower()
            result['restricted'] = 'restrict' in output.lower()
        except (subprocess.TimeoutExpired, FileNotFoundError):
            pass

        result['injectable'] = not result['hardened_runtime'] or not result['library_validation']
        return result

    def _determine_injection_method(self, security):
        """Determine the best injection method"""
        if not security['hardened_runtime']:
            return 'DYLD_INSERT_LIBRARIES (no hardened runtime)'
        elif not security['library_validation']:
            return 'Unsigned dylib load (no library validation)'
        elif not security['restricted']:
            return 'DYLD environment variable (no restrict flag)'
        return 'Unknown'

    def map_iokit_surface(self):
        """Map IOKit user clients accessible on the system"""
        try:
            result = subprocess.run(
                ['ioreg', '-l', '-w', '0'],
                capture_output=True, text=True, timeout=15
            )
            for line in result.stdout.split('\n'):
                if 'UserClient' in line:
                    match = re.search(r'<class (\w+)', line)
                    if match:
                        cls = match.group(1)
                        if cls not in self.iokit_surface:
                            self.iokit_surface[cls] = {
                                'instances': 0,
                                'cve_info': self.IOKIT_CVE_MAP.get(cls, None),
                            }
                        self.iokit_surface[cls]['instances'] += 1
        except (subprocess.TimeoutExpired, FileNotFoundError):
            pass

    def build_chains(self):
        """Construct TCC -> injection -> kernel chains"""
        for client, app_info in self.injectable_apps.items():
            # For each injectable TCC app, check if it can reach a vulnerable IOKit class
            for cls, iokit_info in self.iokit_surface.items():
                cve_data = iokit_info.get('cve_info')
                if not cve_data:
                    continue

                # Chain: TCC app -> inject -> IOKit -> kernel
                chain_score = app_info['max_impact'] * 5 + cve_data['exploitability'] * 10
                if cve_data['kernel_rw']:
                    chain_score += 20

                services_str = ', '.join(s['name'] for s in app_info['tcc_services'][:3])
                cves_str = ', '.join(cve_data['cves'][:2]) if cve_data['cves'] else 'no public CVE'

                chain = {
                    'score': chain_score,
                    'risk': 'CRITICAL' if chain_score >= 100 else 'HIGH',
                    'steps': [
                        {
                            'step': 1,
                            'action': 'TARGET',
                            'detail': '%s (%s)' % (os.path.basename(app_info['binary']), services_str),
                            'tcc_impact': app_info['max_impact'],
                        },
                        {
                            'step': 2,
                            'action': 'INJECT',
                            'detail': app_info['injection_method'],
                            'method': 'dylib_injection',
                        },
                        {
                            'step': 3,
                            'action': 'GAIN_TCC',
                            'detail': 'Inherit: %s' % services_str,
                            'services': [s['service'] for s in app_info['tcc_services']],
                        },
                        {
                            'step': 4,
                            'action': 'REACH_IOKIT',
                            'detail': '%s (%s)' % (cls, cves_str),
                            'vuln_type': cve_data['type'],
                            'kernel_rw': cve_data['kernel_rw'],
                        },
                    ],
                    'narrative': '%s -[%s]-> inherit %s -[IOKit]-> %s (%s) -[%s]-> KERNEL' % (
                        os.path.basename(app_info['binary']),
                        'DYLD' if 'DYLD' in app_info['injection_method'] else 'dylib',
                        services_str,
                        cls, cves_str, cve_data['type'],
                    ),
                }

                self.chains.append(chain)

        # Sort by score
        self.chains.sort(key=lambda c: c['score'], reverse=True)

        # Deduplicate — keep highest-scoring chain per app
        seen_apps = set()
        unique_chains = []
        for chain in self.chains:
            app_name = chain['steps'][0]['detail'].split('(')[0].strip()
            if app_name not in seen_apps:
                seen_apps.add(app_name)
                unique_chains.append(chain)
        self.chains = unique_chains

    def generate_report(self):
        """Generate chain analysis report"""
        return {
            'tcc_apps': len(self.tcc_apps),
            'injectable': len(self.injectable_apps),
            'iokit_classes': len(self.iokit_surface),
            'iokit_with_cves': sum(1 for i in self.iokit_surface.values() if i.get('cve_info')),
            'total_chains': len(self.chains),
            'critical_chains': sum(1 for c in self.chains if c['risk'] == 'CRITICAL'),
            'kernel_rw_chains': sum(1 for c in self.chains if any(
                s.get('kernel_rw') for s in c['steps']
            )),
        }

def demo():
    """Run TCC-to-kernel chain analysis"""
    print("macOS TCC-to-Kernel Privilege Chain Finder v1.0")
    print("=" * 60)

    engine = TCCKernelChainFinder()

    print("\n[Phase 1] Collecting TCC-granted apps...")
    engine.collect_tcc_apps()
    high_impact = sum(1 for a in engine.tcc_apps.values() if a['max_impact'] >= 7)
    print("  TCC apps: %d (%d high-impact)" % (len(engine.tcc_apps), high_impact))

    print("\n[Phase 2] Finding injectable apps...")
    engine.find_injectable_apps()
