    print("  IOKit classes: %d (%d with known CVEs)" % (len(engine.iokit_surface), cve_classes))

    print("\n[Phase 4] Building TCC -> Kernel chains...")
    engine.build_chains()

    report = engine.generate_report()
    print("\n" + "=" * 60)
    print("TCC-TO-KERNEL CHAIN RESULTS")
    print("=" * 60)
    print("  TCC-granted apps: %d" % report['tcc_apps'])
    print("  Injectable apps: %d" % report['injectable'])
    print("  IOKit classes: %d" % report['iokit_classes'])
    print("  IOKit with known CVEs: %d" % report['iokit_with_cves'])
    print("  Total kill chains: %d" % report['total_chains'])
    print("  CRITICAL chains: %d" % report['critical_chains'])
    print("  Kernel R/W chains: %d" % report['kernel_rw_chains'])

    if engine.chains:
        print("\nTop Kill Chains (TCC -> Kernel):")
        print("-" * 60)
        for i, chain in enumerate(engine.chains[:15], 1):
            print("  %2d. [%s] Score %d" % (i, chain['risk'], chain['score']))
            print("      %s" % chain['narrative'][:100])
            for step in chain['steps']:
                print("      Step %d [%s]: %s" % (step['step'], step['action'], step['detail'][:60]))
            print()

    # Injectable app details
    if engine.injectable_apps:
        print("Injectable TCC Apps (top 10):")
        sorted_apps = sorted(engine.injectable_apps.items(),
                            key=lambda x: x[1]['max_impact'], reverse=True)
        for client, info in sorted_apps[:10]:
            hr = 'HR' if info['security']['hardened_runtime'] else 'NO-HR'
            lv = 'LV' if info['security']['library_validation'] else 'NO-LV'
            services = ', '.join(s['name'] for s in info['tcc_services'][:3])
            name = os.path.basename(info['binary'])
            print("  [P%d] %s [%s, %s]: %s" % (info['max_impact'], name[:30], hr, lv, services))

    print("\nTCC-to-kernel chain analysis complete")

demo()

