import os, subprocess, struct, sqlite3, stat, re, time, json
from collections import defaultdict
from pathlib import Path

class VulnDiscoveryDashboard:
    """Unified vulnerability discovery dashboard — orchestrates all engines"""

    def __init__(self):
        self.results = {}
        self.all_findings = []
        self.start_time = time.time()

    def run_iokit_scan(self):
        """IOKit user client enumeration"""
        print("\n[1/8] IOKit User Client Scan")
        findings = []
        clients = {}
        CVE_CLASSES = {
            'IOSurfaceRootUserClient': ['CVE-2021-30807', 'CVE-2023-38606'],
            'AGXCommandQueue': ['CVE-2023-32434'],
            'IOHIDEventServiceUserClient': ['CVE-2016-4654'],
            'AppleAVEDriver': ['CVE-2022-32893'],
            'IOMobileFramebufferUserClient': ['CVE-2021-30883'],
            'AppleKeyStoreUserClient': ['CVE-2020-9839'],
        }
        try:
            result = subprocess.run(['ioreg', '-l', '-w', '0'],
                                    capture_output=True, text=True, timeout=15)
            for line in result.stdout.split('\n'):
                if 'UserClient' in line:
                    match = re.search(r'<class (\w+)', line)
                    if match:
                        cls = match.group(1)
                        clients[cls] = clients.get(cls, 0) + 1
        except (subprocess.TimeoutExpired, FileNotFoundError):
            pass

        cve_count = 0
        for cls, count in clients.items():
            if cls in CVE_CLASSES:
                cve_count += 1
                for cve in CVE_CLASSES[cls]:
                    findings.append({
                        'severity': 'CRITICAL',
                        'category': 'IOKIT',
                        'detail': '%s (%d instances) — %s' % (cls, count, cve),
                    })

        self.results['iokit'] = {
            'user_clients': len(clients),
            'total_instances': sum(clients.values()),
            'cve_affected': cve_count,
            'findings': len(findings),
        }
        self.all_findings.extend(findings)
        print("  Classes: %d | CVE-affected: %d | Findings: %d" % (
            len(clients), cve_count, len(findings)))

    def run_tcc_scan(self):
        """TCC grant analysis + injection potential"""
        print("\n[2/8] TCC & Injection Analysis")
        tcc_apps = {}
        tcc_paths = [
            os.path.expanduser('~/Library/Application Support/com.apple.TCC/TCC.db'),
            '/Library/Application Support/com.apple.TCC/TCC.db',
        ]
        for tcc_path in tcc_paths:
            if not os.path.exists(tcc_path):
                continue
            try:
                conn = sqlite3.connect('file:%s?mode=ro' % tcc_path, uri=True)
                cursor = conn.execute("SELECT client, service FROM access WHERE auth_value = 2")
                for client, service in cursor:
                    if client not in tcc_apps:
                        tcc_apps[client] = []
                    tcc_apps[client].append(service)
                conn.close()
            except (sqlite3.OperationalError, sqlite3.DatabaseError):
                pass

        # Check injectability of TCC apps
        injectable = 0
        findings = []
        fda_apps = []
        for client, services in tcc_apps.items():
            has_fda = any('AllFiles' in s for s in services)
            if has_fda:
                fda_apps.append(client)

            # Try to find and check binary
            binary = self._find_binary(client)
            if binary and os.path.exists(binary):
                try:
                    r = subprocess.run(['codesign', '-dvv', binary],
                                       capture_output=True, text=True, timeout=5)
                    output = r.stderr.lower()
                    hr = 'runtime' in output
                    lv = 'library-validation' in output
                    if not hr or not lv:
                        injectable += 1
                        if has_fda:
                            findings.append({
                                'severity': 'CRITICAL',
                                'category': 'TCC_INJECTION',
                                'detail': '%s: FDA + %s' % (
                                    os.path.basename(binary),
                                    'NO-HR' if not hr else 'NO-LV',
                                ),
                            })
                except (subprocess.TimeoutExpired, FileNotFoundError):
                    pass

        self.results['tcc'] = {
            'tcc_apps': len(tcc_apps),
            'fda_apps': len(fda_apps),
            'injectable': injectable,
            'findings': len(findings),
        }
        self.all_findings.extend(findings)
        print("  TCC apps: %d | FDA: %d | Injectable: %d | Findings: %d" % (
            len(tcc_apps), len(fda_apps), injectable, len(findings)))

    def run_sandbox_scan(self):
        """Sandbox profile cross-reference"""
        print("\n[3/8] Sandbox Profile Analysis")
        profiles_dir = '/System/Library/Sandbox/Profiles'
        profiles = []
        mach_services = set()
        dynamic_code = []

        if os.path.isdir(profiles_dir):
            for item in os.listdir(profiles_dir):
                if item.endswith('.sb'):
                    profiles.append(item)
                    full = os.path.join(profiles_dir, item)
                    try:
                        with open(full, 'r') as f:
                            content = f.read()
                        # Count mach-lookup
                        for m in re.finditer(r'mach-lookup.*?"([^"]+)"', content):
                            mach_services.add(m.group(1))
                        # Dynamic code
                        if 'dynamic-code-generation' in content:
                            dynamic_code.append(item.replace('.sb', ''))
                    except (PermissionError, UnicodeDecodeError):
                        pass

        findings = []
        for dc in dynamic_code:
            findings.append({
                'severity': 'HIGH',
                'category': 'SANDBOX',
                'detail': '%s: allows dynamic code generation' % dc,
            })

        self.results['sandbox'] = {
            'profiles': len(profiles),
            'mach_services': len(mach_services),
            'dynamic_code': len(dynamic_code),
            'findings': len(findings),
        }
        self.all_findings.extend(findings)
        print("  Profiles: %d | Mach services: %d | Dynamic code: %d" % (
            len(profiles), len(mach_services), len(dynamic_code)))

    def run_amfi_scan(self):
        """AMFI policy and binary security scan"""
        print("\n[4/8] AMFI & Code Signing Analysis")
        scan_dirs = ['/usr/bin', '/usr/sbin', '/sbin', '/bin']
        total = 0
        no_hr = 0
        suid_no_hr = 0
        suid_bins = []
        findings = []

        for scan_dir in scan_dirs:
            if not os.path.isdir(scan_dir):
                continue
            for item in os.listdir(scan_dir):
                full = os.path.join(scan_dir, item)
                if not os.path.isfile(full) or os.path.islink(full):
                    continue
                try:
                    with open(full, 'rb') as f:
                        magic = f.read(4)
                    if magic not in (b'\xcf\xfa\xed\xfe', b'\xce\xfa\xed\xfe', b'\xca\xfe\xba\xbe'):
                        continue
                except (PermissionError, OSError):
                    continue

                total += 1
                is_suid = bool(os.stat(full).st_mode & stat.S_ISUID)
                try:
                    r = subprocess.run(['codesign', '-dvv', full],
                                       capture_output=True, text=True, timeout=5)
                    hr = 'runtime' in r.stderr.lower()
                    if not hr:
                        no_hr += 1
                        if is_suid:
                            suid_no_hr += 1
                            suid_bins.append(item)
                            findings.append({
                                'severity': 'CRITICAL',
                                'category': 'AMFI',
                                'detail': 'SUID + NO-HR: %s' % full,
                            })
                except (subprocess.TimeoutExpired, FileNotFoundError):
                    pass

        # Check developer mode
        dev_mode = False
        try:
            r = subprocess.run(['sysctl', 'security.mac.amfi.developer_mode_status'],
                               capture_output=True, text=True, timeout=5)
            if r.returncode == 0 and '1' in r.stdout:
                dev_mode = True
                findings.append({
                    'severity': 'CRITICAL',
                    'category': 'AMFI',
                    'detail': 'Developer Mode ENABLED — AMFI enforcement relaxed',
                })
        except (subprocess.TimeoutExpired, FileNotFoundError):
            pass

        self.results['amfi'] = {
            'total_binaries': total,
            'no_hardened_runtime': no_hr,
            'no_hr_percent': round(100 * no_hr / max(total, 1)),
            'suid_no_hr': suid_no_hr,
            'developer_mode': dev_mode,
            'findings': len(findings),
        }
        self.all_findings.extend(findings)
        print("  Binaries: %d | NO-HR: %d (%d%%) | SUID+NO-HR: %d | DevMode: %s" % (
            total, no_hr, self.results['amfi']['no_hr_percent'],
            suid_no_hr, 'YES' if dev_mode else 'NO'))

    def run_xpc_scan(self):
        """XPC service enumeration"""
        print("\n[5/8] XPC Service Analysis")
        services = 0
        unsigned = 0
        findings = []

        for plist_dir in ['/System/Library/LaunchDaemons', '/Library/LaunchDaemons',
                          '/System/Library/LaunchAgents', '/Library/LaunchAgents']:
            if not os.path.isdir(plist_dir):
                continue
            for item in os.listdir(plist_dir):
                if not item.endswith('.plist'):
                    continue
                services += 1

        # Check for unsigned service binaries
        for plist_dir in ['/Library/LaunchDaemons', '/Library/LaunchAgents']:
            if not os.path.isdir(plist_dir):
                continue
            for item in os.listdir(plist_dir):
                if not item.endswith('.plist'):
                    continue
                full = os.path.join(plist_dir, item)
                try:
                    import plistlib
                    with open(full, 'rb') as f:
                        plist = plistlib.load(f)
                    program = plist.get('Program', '')
                    if not program and 'ProgramArguments' in plist:
                        args = plist.get('ProgramArguments', [])
                        program = args[0] if args else ''
                    if program and os.path.exists(program):
                        r = subprocess.run(['codesign', '-v', program],
                                           capture_output=True, timeout=5)
                        if r.returncode != 0:
                            unsigned += 1
                            findings.append({
                                'severity': 'HIGH',
                                'category': 'XPC',
                                'detail': 'Unsigned: %s' % os.path.basename(program),
                            })
                except Exception:
                    pass

        self.results['xpc'] = {
            'total_services': services,
            'unsigned': unsigned,
            'findings': len(findings),
        }
        self.all_findings.extend(findings)
        print("  Services: %d | Unsigned: %d" % (services, unsigned))

    def run_dylib_scan(self):
        """Dylib hijack quick scan"""
        print("\n[6/8] Dylib Hijack Scan")
        targets = 0
        rpath_count = 0
        findings = []

        for app_dir in ['/Applications']:
            if not os.path.isdir(app_dir):
                continue
            for item in os.listdir(app_dir):
                if not item.endswith('.app'):
                    continue
                macos_dir = os.path.join(app_dir, item, 'Contents', 'MacOS')
                if not os.path.isdir(macos_dir):
                    continue
                bins = os.listdir(macos_dir)
                if not bins:
                    continue
                binary = os.path.join(macos_dir, bins[0])
                if not os.path.isfile(binary):
                    continue

                try:
                    r = subprocess.run(['otool', '-L', binary],
                                       capture_output=True, text=True, timeout=10)
                    rpaths = sum(1 for line in r.stdout.split('\n') if '@rpath' in line)
                    if rpaths > 0:
                        targets += 1
                        rpath_count += rpaths
                except (subprocess.TimeoutExpired, FileNotFoundError):
                    pass

        self.results['dylib'] = {
            'hijack_targets': targets,
            'rpath_references': rpath_count,
            'findings': len(findings),
        }
        self.all_findings.extend(findings)
        print("  Hijack targets: %d | @rpath refs: %d" % (targets, rpath_count))

    def run_pattern_scan(self):
        """Quick pattern scan on critical binaries"""
        print("\n[7/8] Binary Pattern Scan (critical binaries)")
        MH_MAGIC_64 = 0xFEEDFACF
        FAT_MAGIC_BE = 0xCAFEBABE
        LC_SEGMENT_64 = 0x19
        targets = ['/usr/libexec/amfid', '/usr/libexec/trustd',
                   '/usr/libexec/syspolicyd', '/usr/sbin/securityd']
        existing = [t for t in targets if os.path.exists(t)]

        overflow_total = 0
        findings = []

        for target in existing:
            try:
                with open(target, 'rb') as f:
                    data = f.read()
            except PermissionError:
                continue

            # Handle fat binary
            if len(data) >= 8 and struct.unpack('>I', data[:4])[0] == FAT_MAGIC_BE:
                nfat = struct.unpack('>I', data[4:8])[0]
                for i in range(min(nfat, 8)):
                    off = 8 + i * 20
                    cpu = struct.unpack('>I', data[off:off+4])[0]
                    arch_off = struct.unpack('>I', data[off+8:off+12])[0]
                    arch_size = struct.unpack('>I', data[off+12:off+16])[0]
                    if cpu == 0x100000C:
                        data = data[arch_off:arch_off+arch_size]
                        break

            if len(data) < 32 or struct.unpack('<I', data[:4])[0] != MH_MAGIC_64:
                continue

            # Find __text
            ncmds = struct.unpack('<I', data[16:20])[0]
            offset = 32
            text_off = text_size = 0
            for _ in range(min(ncmds, 256)):
                if offset + 8 > len(data):
                    break
                cmd, cmdsize = struct.unpack('<II', data[offset:offset+8])
                if cmdsize < 8:
                    break
                if cmd == LC_SEGMENT_64 and offset + 72 <= len(data):
                    segname = data[offset+8:offset+24].split(b'\x00')[0].decode('utf-8', errors='replace')
                    if segname == '__TEXT':
                        nsects = struct.unpack('<I', data[offset+64:offset+68])[0]
                        sec_off = offset + 72
                        for _ in range(min(nsects, 256)):
                            if sec_off + 80 > len(data):
                                break
                            sec_name = data[sec_off:sec_off+16].split(b'\x00')[0].decode('utf-8', errors='replace')
                            if sec_name == '__text':
                                text_off = struct.unpack('<I', data[sec_off+48:sec_off+52])[0]
                                text_size = struct.unpack('<Q', data[sec_off+40:sec_off+48])[0]
                            sec_off += 80
                offset += cmdsize

            if not text_off:
                continue

            # Scan for MUL → BL without bounds check
            overflow_count = 0
            text_data = data[text_off:text_off + text_size]
            for i in range(0, len(text_data) - 32, 4):
                word = struct.unpack('<I', text_data[i:i+4])[0]
                # MUL pattern
                if (word & 0x7FE0FC00) == 0x1B007C00:
                    has_check = False
                    for j in range(1, 9):
                        noff = i + j * 4
                        if noff + 4 > len(text_data):
                            break
                        nw = struct.unpack('<I', text_data[noff:noff+4])[0]
                        if (nw & 0xFF000010) == 0x54000000:  # B.cond
                            has_check = True
                            break
                        if (nw & 0xFC000000) == 0x94000000 and not has_check:  # BL
                            overflow_count += 1
                            break
            if overflow_count > 0:
                overflow_total += overflow_count
                findings.append({
                    'severity': 'HIGH',
                    'category': 'PATTERN',
                    'detail': '%s: %d integer overflow patterns' % (
                        os.path.basename(target), overflow_count),
                })

