            'findings': len(findings),
        }
        self.all_findings.extend(findings)
        print("  Scanned: %d | Overflow patterns: %d" % (len(existing), overflow_total))

    def run_chain_analysis(self):
        """Quick kill chain construction"""
        print("\n[8/8] Kill Chain Construction")
        chains = 0
        critical = 0
