    def _find_binary(self, client):
        """Resolve TCC client to binary path"""
        if client.startswith('/'):
            return client
        app_name = client.split('.')[-1]
        for candidate in ['/Applications/%s.app/Contents/MacOS/%s' % (app_name, app_name),
