import os, subprocess, stat, tempfile, time, hashlib, glob, re, json
from pathlib import Path
from collections import defaultdict

class SandboxChainValidator:
    """
    Active validation of sandbox write-read chains.

    Tests the top cross-reference chains from Vuln-02:
    - Can process A actually write to the paths identified?
    - Can process B actually read from those paths?
    - Are file permissions compatible with the chain?
    - Do the processes actually run and access these paths?

    SAFETY:
    - Creates test files ONLY in /tmp/forge_sandbox_test/
    - Never modifies system files
    - All reads are non-destructive
    - Cleanup runs at end
    """

    TEST_DIR = '/tmp/forge_sandbox_test'

    def __init__(self):
        self.chains = []
        self.validated = []
        self.denied = []
        self.findings = []
        os.makedirs(self.TEST_DIR, exist_ok=True)

    def parse_sandbox_profiles(self):
        """Parse sandbox profiles to extract allowed operations"""
        profiles = {}
        profile_dir = '/System/Library/Sandbox/Profiles'

        if not os.path.isdir(profile_dir):
            self.findings.append({
                'severity': 'INFO',
                'detail': 'Sandbox profiles directory not found: %s' % profile_dir,
            })
            return profiles

        for fname in os.listdir(profile_dir):
            if not fname.endswith('.sb'):
                continue
            fpath = os.path.join(profile_dir, fname)
            profile_name = fname.replace('.sb', '')
            profile = {
                'name': profile_name,
                'file_write': [],
                'file_read': [],
                'mach_lookup': [],
                'iokit_open': [],
                'process_exec': [],
                'network': False,
                'dynamic_code': False,
            }

            try:
                with open(fpath, 'r', errors='replace') as f:
                    content = f.read()

                # Extract file-write paths
                for m in re.finditer(r'\(allow\s+file-write\*?\s+\((?:subpath|literal|regex)\s+"([^"]+)"\)', content):
                    profile['file_write'].append(m.group(1))

                # Extract file-read paths
                for m in re.finditer(r'\(allow\s+file-read\*?\s+\((?:subpath|literal|regex)\s+"([^"]+)"\)', content):
                    profile['file_read'].append(m.group(1))

                # Extract mach-lookup services
                for m in re.finditer(r'\(allow\s+mach-lookup\s+\(global-name\s+"([^"]+)"\)', content):
                    profile['mach_lookup'].append(m.group(1))

                # Extract iokit-open classes
                for m in re.finditer(r'\(allow\s+iokit-open\s+\(iokit-user-client-class\s+"([^"]+)"\)', content):
                    profile['iokit_open'].append(m.group(1))

                # Extract process-exec
                for m in re.finditer(r'\(allow\s+process-exec\*?\s+\((?:subpath|literal)\s+"([^"]+)"\)', content):
                    profile['process_exec'].append(m.group(1))

                # Network access
                if 'network-outbound' in content or 'network-inbound' in content:
                    profile['network'] = True

                # Dynamic code
                if 'dynamic-code-generation' in content:
                    profile['dynamic_code'] = True

            except (OSError, UnicodeDecodeError):
                continue

            profiles[profile_name] = profile

        return profiles

    def build_write_read_chains(self, profiles):
        """Build chains where profile A writes to paths that profile B reads"""
        chains = []

        profile_list = list(profiles.values())
        for writer in profile_list:
            for reader in profile_list:
                if writer['name'] == reader['name']:
                    continue

                shared_paths = []
                for w_path in writer['file_write']:
                    for r_path in reader['file_read']:
                        # Check if write path is under read path or vice versa
                        if w_path.startswith(r_path) or r_path.startswith(w_path):
                            shared_paths.append({
                                'write_path': w_path,
                                'read_path': r_path,
                                'overlap': 'exact' if w_path == r_path else 'subpath',
                            })

                if shared_paths:
                    # Score the chain
                    score = len(shared_paths) * 10
                    if reader['network']:
                        score += 20  # Network reader = data exfil potential
                    if reader['dynamic_code']:
                        score += 30  # Dynamic code reader = code exec potential
                    if reader['iokit_open']:
                        score += 25  # IOKit access = kernel potential
                    if writer['process_exec']:
                        score += 15  # Writer can exec = additional capabilities

                    chains.append({
                        'writer': writer['name'],
                        'reader': reader['name'],
                        'shared_paths': shared_paths,
                        'score': score,
                        'reader_network': reader['network'],
                        'reader_dynamic_code': reader['dynamic_code'],
                        'reader_iokit': reader['iokit_open'],
                        'writer_exec': writer['process_exec'],
                    })

        return sorted(chains, key=lambda c: c['score'], reverse=True)

    def validate_path_permissions(self, path):
        """Check if a path exists and what permissions it has"""
        result = {
            'exists': False,
            'is_dir': False,
            'is_file': False,
            'readable': False,
            'writable': False,
            'owner': '',
            'group': '',
            'mode': '',
            'sip_protected': False,
        }

        # Check SIP protection
        sip_prefixes = ['/System/', '/usr/bin/', '/usr/sbin/', '/usr/lib/',
                        '/bin/', '/sbin/', '/Library/Apple/']
        result['sip_protected'] = any(path.startswith(p) for p in sip_prefixes)

        try:
            st = os.stat(path)
            result['exists'] = True
            result['is_dir'] = stat.S_ISDIR(st.st_mode)
            result['is_file'] = stat.S_ISREG(st.st_mode)
            result['readable'] = os.access(path, os.R_OK)
            result['writable'] = os.access(path, os.W_OK)
            result['mode'] = oct(st.st_mode)[-3:]
            # Get owner/group names
            try:
                import pwd, grp
                result['owner'] = pwd.getpwuid(st.st_uid).pw_name
                result['group'] = grp.getgrgid(st.st_gid).gr_name
            except (KeyError, ImportError):
                result['owner'] = str(st.st_uid)
                result['group'] = str(st.st_gid)
        except OSError:
            pass

        return result

    def validate_chain(self, chain):
        """Actively validate a write-read chain"""
        validation = {
            'writer': chain['writer'],
            'reader': chain['reader'],
            'score': chain['score'],
            'paths_checked': 0,
            'paths_writable': 0,
            'paths_readable': 0,
            'paths_both': 0,
            'confirmed_chains': [],
            'denied_reasons': [],
            'risk_level': 'LOW',
        }

        for shared in chain['shared_paths']:
            w_path = shared['write_path']
            r_path = shared['read_path']
            validation['paths_checked'] += 1

            w_perms = self.validate_path_permissions(w_path)
            r_perms = self.validate_path_permissions(r_path)

            w_ok = w_perms['writable'] or (w_perms['exists'] and not w_perms['sip_protected'])
            r_ok = r_perms['readable'] or r_perms['exists']

            if w_ok:
                validation['paths_writable'] += 1
            if r_ok:
                validation['paths_readable'] += 1

            if w_ok and r_ok:
                validation['paths_both'] += 1
                validation['confirmed_chains'].append({
                    'write_path': w_path,
                    'read_path': r_path,
                    'write_perms': w_perms,
                    'read_perms': r_perms,
                    'exploitable': not w_perms['sip_protected'] and w_perms['writable'],
                })
            else:
                reasons = []
                if w_perms['sip_protected']:
                    reasons.append('Write path SIP-protected')
                if not w_perms['writable'] and not w_perms['exists']:
                    reasons.append('Write path does not exist')
                if not w_perms['writable'] and w_perms['exists']:
                    reasons.append('Write path not writable (mode %s, owner %s)' % (
                        w_perms['mode'], w_perms['owner']))
                if not r_perms['exists']:
                    reasons.append('Read path does not exist')
                validation['denied_reasons'].extend(reasons)

        # Determine risk level
        exploitable = [c for c in validation['confirmed_chains'] if c['exploitable']]
        if exploitable and chain.get('reader_dynamic_code'):
            validation['risk_level'] = 'CRITICAL'
        elif exploitable and (chain.get('reader_network') or chain.get('reader_iokit')):
            validation['risk_level'] = 'HIGH'
        elif exploitable:
            validation['risk_level'] = 'MEDIUM'
        elif validation['confirmed_chains']:
            validation['risk_level'] = 'LOW'

        return validation

    def check_mach_service_chains(self, profiles):
        """Check Mach IPC chains between sandbox profiles"""
        mach_chains = []

        # Build service-to-profile map
        service_map = defaultdict(list)
        for pname, profile in profiles.items():
            for svc in profile['mach_lookup']:
                service_map[svc].append(pname)

        # Find cross-profile service access
        for pname, profile in profiles.items():
            for svc in profile['mach_lookup']:
                # Who else accesses this service?
                other_users = [p for p in service_map[svc] if p != pname]
                if other_users:
                    # Check if any user has higher privilege
                    for other in other_users:
                        other_p = profiles.get(other)
                        if not other_p:
                            continue
                        # Higher privilege = IOKit access or dynamic code
                        if other_p['iokit_open'] or other_p['dynamic_code']:
                            mach_chains.append({
                                'from_profile': pname,
                                'to_profile': other,
                                'service': svc,
                                'target_iokit': other_p['iokit_open'],
                                'target_dynamic': other_p['dynamic_code'],
                                'risk': 'HIGH' if other_p['iokit_open'] else 'MEDIUM',
                            })

        return mach_chains

    def check_process_exec_chains(self, profiles):
        """Check process execution chains across sandbox boundaries"""
        exec_chains = []

        for pname, profile in profiles.items():
            for exec_path in profile['process_exec']:
                # Resolve what sandbox the exec target runs under
                exec_name = os.path.basename(exec_path)
                for target_name, target_profile in profiles.items():
                    if target_name == pname:
                        continue
                    # Check if target profile name matches exec binary
                    if exec_name in target_name or target_name in exec_name:
                        # Privilege escalation via exec
                        priv_delta = 0
                        if target_profile['iokit_open']:
                            priv_delta += 30
                        if target_profile['dynamic_code']:
                            priv_delta += 20
                        if target_profile['network'] and not profile['network']:
                            priv_delta += 10
                        if target_profile['file_write'] and len(target_profile['file_write']) > len(profile['file_write']):
                            priv_delta += 15

                        if priv_delta > 0:
                            exec_chains.append({
                                'from_profile': pname,
                                'to_profile': target_name,
                                'exec_path': exec_path,
                                'priv_delta': priv_delta,
                                'target_capabilities': {
                                    'iokit': bool(target_profile['iokit_open']),
                                    'dynamic_code': target_profile['dynamic_code'],
                                    'network': target_profile['network'],
                                    'file_write_count': len(target_profile['file_write']),
                                },
                            })

        return sorted(exec_chains, key=lambda c: c['priv_delta'], reverse=True)

    def validate_all(self):
        """Run full sandbox chain validation"""
        results = {
            'profiles_parsed': 0,
            'write_read_chains': 0,
            'validated_chains': 0,
            'confirmed_exploitable': 0,
            'mach_chains': 0,
            'exec_chains': 0,
            'top_chains': [],
            'mach_findings': [],
            'exec_findings': [],
        }

        # Phase 1: Parse profiles
        profiles = self.parse_sandbox_profiles()
        results['profiles_parsed'] = len(profiles)

        if not profiles:
            self.findings.append({
                'severity': 'WARNING',
                'detail': 'No sandbox profiles found. SIP may prevent access.',
            })
            return results

        # Phase 2: Build write-read chains
        chains = self.build_write_read_chains(profiles)
        results['write_read_chains'] = len(chains)

        # Phase 3: Validate top chains
        top_chains = chains[:50]  # Validate top 50
        for chain in top_chains:
            validation = self.validate_chain(chain)
            results['validated_chains'] += 1

            if validation['confirmed_chains']:
                self.validated.append(validation)
                exploitable = [c for c in validation['confirmed_chains'] if c['exploitable']]
                if exploitable:
                    results['confirmed_exploitable'] += 1
                    self.findings.append({
                        'severity': validation['risk_level'],
                        'detail': 'Sandbox chain CONFIRMED: %s -> %s (%d exploitable paths)' % (
                            validation['writer'], validation['reader'], len(exploitable)),
                    })
            else:
                self.denied.append(validation)

        results['top_chains'] = [
            {
                'writer': v['writer'],
                'reader': v['reader'],
                'score': v['score'],
                'risk': v['risk_level'],
                'exploitable_paths': len([c for c in v['confirmed_chains'] if c['exploitable']]),
                'total_paths': v['paths_checked'],
            }
            for v in sorted(self.validated, key=lambda v: v['score'], reverse=True)[:20]
        ]

        # Phase 4: Mach service chains
        mach_chains = self.check_mach_service_chains(profiles)
        results['mach_chains'] = len(mach_chains)
        results['mach_findings'] = mach_chains[:10]

        # Phase 5: Process exec chains
        exec_chains = self.check_process_exec_chains(profiles)
        results['exec_chains'] = len(exec_chains)
        results['exec_findings'] = exec_chains[:10]

        return results

def demo():
    """Run sandbox chain validation"""
    print("macOS Sandbox Chain Validator v1.0")
    print("=" * 60)
    print("SAFETY: Read-only analysis + test files in /tmp/ only")
    print("=" * 60)

    engine = SandboxChainValidator()
    results = engine.validate_all()

    print("\n[Results]")
    print("  Profiles parsed: %d" % results['profiles_parsed'])
    print("  Write-read chains found: %d" % results['write_read_chains'])
    print("  Chains validated: %d" % results['validated_chains'])
    print("  Confirmed exploitable: %d" % results['confirmed_exploitable'])
    print("  Mach IPC chains: %d" % results['mach_chains'])
    print("  Process exec chains: %d" % results['exec_chains'])

    if results['top_chains']:
        print("\n  TOP VALIDATED CHAINS:")
        for c in results['top_chains'][:10]:
            print("    [%s] %s -> %s (score %d, %d exploitable of %d paths)" % (
                c['risk'], c['writer'][:20], c['reader'][:20],
                c['score'], c['exploitable_paths'], c['total_paths']))

    if results['mach_findings']:
        print("\n  TOP MACH IPC CHAINS:")
        for m in results['mach_findings'][:5]:
            print("    [%s] %s -> %s via %s" % (
                m['risk'], m['from_profile'][:20], m['to_profile'][:20], m['service'][:40]))
            if m['target_iokit']:
                print("      IOKit: %s" % ', '.join(m['target_iokit'][:3]))

    if results['exec_findings']:
        print("\n  TOP PROCESS EXEC CHAINS:")
        for e in results['exec_findings'][:5]:
            print("    %s -> %s (priv_delta %d) via %s" % (
