import os, subprocess, re, struct, hashlib
from collections import defaultdict

class XPCMethodEnumerator:
    """
    XPC service method enumeration for macOS security analysis.

    Extracts XPC interface methods from service binaries using:
    1. otool -oV to dump Objective-C class/protocol metadata
    2. Parsing @protocol declarations for NSXPCConnection interfaces
    3. nm symbol extraction for XPC-related selectors
    4. Cross-referencing with launchd plist configurations

    SAFETY: Read-only analysis. No connections made.
    MEMORY-SAFE: Processes one binary at a time, small output.
    """

    XPC_DIRS = [
        '/System/Library/LaunchDaemons',
        '/System/Library/LaunchAgents',
        '/Library/LaunchDaemons',
        '/Library/LaunchAgents',
    ]

    # High-value XPC services for security research
    HIGH_VALUE = [
        'com.apple.trustd',
        'com.apple.security',
        'com.apple.securityd',
        'com.apple.tccd',
        'com.apple.syspolicyd',
        'com.apple.amfid',
        'com.apple.sandboxd',
        'com.apple.opendirectoryd',
        'com.apple.coreservices',
        'com.apple.mdmclient',
    ]

    def __init__(self):
        self.findings = []
        self.services = {}

    def parse_launchd_plists(self):
        """Extract XPC service configurations from launchd plists"""
        services = {}

        for plist_dir in self.XPC_DIRS:
            if not os.path.isdir(plist_dir):
                continue

            for fname in os.listdir(plist_dir):
                if not fname.endswith('.plist'):
                    continue

                fpath = os.path.join(plist_dir, fname)
                svc_name = fname.replace('.plist', '')

                svc = {
                    'name': svc_name,
                    'plist': fpath,
                    'binary': '',
                    'mach_services': [],
                    'type': 'daemon' if 'Daemon' in plist_dir else 'agent',
                }

                # Parse plist for binary path and mach services
                try:
                    r = subprocess.run(['/usr/bin/plutil', '-convert', 'xml1', '-o', '-', fpath],
                                       capture_output=True, text=True, timeout=5)
                    if r.returncode == 0:
                        content = r.stdout

                        # Extract ProgramArguments or Program
                        m = re.search(r'<key>Program</key>\s*<string>([^<]+)</string>', content)
                        if m:
                            svc['binary'] = m.group(1)
                        else:
                            # ProgramArguments - first string after the key
                            m = re.search(r'<key>ProgramArguments</key>\s*<array>\s*<string>([^<]+)</string>', content)
                            if m:
                                svc['binary'] = m.group(1)

                        # Extract MachServices
                        ms_match = re.search(r'<key>MachServices</key>\s*<dict>(.*?)</dict>', content, re.DOTALL)
                        if ms_match:
                            for key_m in re.finditer(r'<key>([^<]+)</key>', ms_match.group(1)):
                                svc['mach_services'].append(key_m.group(1))

                except (subprocess.TimeoutExpired, FileNotFoundError):
                    pass

                if svc['binary'] or svc['mach_services']:
                    services[svc_name] = svc

        return services

    def extract_objc_protocols(self, binary_path):
        """Extract Objective-C protocol declarations (XPC interfaces)"""
        protocols = []

        if not os.path.exists(binary_path):
            return protocols

        # Use otool -oV to get Objective-C metadata (lightweight, just metadata section)
        try:
            r = subprocess.run(['otool', '-arch', 'arm64e', '-oV', binary_path],
                               capture_output=True, text=True, timeout=15)
            if r.returncode != 0:
                r = subprocess.run(['otool', '-arch', 'x86_64', '-oV', binary_path],
                                   capture_output=True, text=True, timeout=15)

            if r.returncode == 0:
                current_protocol = None
                current_methods = []

                for line in r.stdout.splitlines():
                    # Protocol definition
                    pm = re.match(r'\s*name\s+0x[0-9a-f]+\s+(\S+)', line)
                    if pm and 'Protocol' not in line:
                        if current_protocol and current_methods:
                            protocols.append({
                                'name': current_protocol,
                                'methods': current_methods[:],
                            })
                        current_protocol = pm.group(1)
                        current_methods = []

                    # Method name
                    mm = re.match(r'\s+name\s+0x[0-9a-f]+\s+(\S+)', line)
                    if mm and current_protocol:
                        method = mm.group(1)
                        if ':' in method:  # ObjC selector
                            current_methods.append(method)

                if current_protocol and current_methods:
                    protocols.append({
                        'name': current_protocol,
                        'methods': current_methods,
                    })

        except (subprocess.TimeoutExpired, FileNotFoundError):
            pass

        return protocols

    def extract_xpc_selectors(self, binary_path):
        """Extract XPC-related selectors via nm"""
        selectors = []

        if not os.path.exists(binary_path):
            return selectors

        for arch in ['arm64e', 'x86_64']:
            try:
                r = subprocess.run(['nm', '-arch', arch, binary_path],
                                   capture_output=True, text=True, timeout=10)
                if r.returncode != 0:
                    continue

                for line in r.stdout.splitlines():
                    parts = line.strip().split()
                    if len(parts) >= 3:
                        sym = parts[2]
                        # Look for XPC-related selectors
                        if any(kw in sym.lower() for kw in ['xpc', 'nsxpc', 'connection', 'interface', 'protocol']):
                            selectors.append(sym)
                break
            except (subprocess.TimeoutExpired, FileNotFoundError):
                pass

        return selectors

    def analyze_service(self, svc):
        """Analyze a single XPC service"""
        result = {
            'name': svc['name'],
            'binary': svc['binary'],
            'type': svc['type'],
            'mach_services': svc['mach_services'],
            'protocols': [],
            'xpc_selectors': [],
            'methods_count': 0,
            'score': 0,
            'reasons': [],
        }

        if not svc['binary'] or not os.path.exists(svc['binary']):
            return result

        # Extract ObjC protocols
        protocols = self.extract_objc_protocols(svc['binary'])
        result['protocols'] = protocols
        result['methods_count'] = sum(len(p['methods']) for p in protocols)

        # Extract XPC selectors
        selectors = self.extract_xpc_selectors(svc['binary'])
        result['xpc_selectors'] = selectors[:20]  # Limit

        # Score
        if result['methods_count'] > 0:
            result['score'] += 10
            result['reasons'].append('%d_methods' % result['methods_count'])

        if result['type'] == 'daemon':
            result['score'] += 10
            result['reasons'].append('daemon(root)')

        if any(hv in svc['name'] for hv in self.HIGH_VALUE):
            result['score'] += 20
            result['reasons'].append('high_value')

        if len(svc['mach_services']) > 1:
            result['score'] += 5
            result['reasons'].append('%d_mach_services' % len(svc['mach_services']))

        # XPC-related symbols
        xpc_count = len(selectors)
        if xpc_count > 5:
            result['score'] += 10
            result['reasons'].append('%d_xpc_symbols' % xpc_count)

        return result

    def run_analysis(self):
        """Run full XPC method enumeration"""
        results = {
            'services_found': 0,
            'services_with_binary': 0,
            'total_protocols': 0,
            'total_methods': 0,
            'daemons': 0,
            'agents': 0,
            'top_services': [],
        }

        # Parse launchd plists
        services = self.parse_launchd_plists()
        results['services_found'] = len(services)

        all_analyzed = []

        for svc_name, svc in services.items():
            if svc['binary']:
                results['services_with_binary'] += 1

            if svc['type'] == 'daemon':
                results['daemons'] += 1
            else:
                results['agents'] += 1

            # Only analyze services with binaries
            if svc['binary'] and os.path.exists(svc['binary']):
                analysis = self.analyze_service(svc)
                results['total_protocols'] += len(analysis['protocols'])
                results['total_methods'] += analysis['methods_count']
                all_analyzed.append(analysis)

        # Sort by score
        all_analyzed.sort(key=lambda a: a['score'], reverse=True)
        results['top_services'] = all_analyzed[:25]

        # Findings for high-score services
        for svc in all_analyzed[:10]:
            if svc['score'] >= 20:
                self.findings.append({
                    'severity': 'HIGH' if svc['score'] >= 30 else 'MEDIUM',
                    'detail': 'XPC: %s (%d methods, %d protocols) %s' % (
                        svc['name'][:30], svc['methods_count'],
                        len(svc['protocols']), ','.join(svc['reasons'][:3])),
                })

        return results


def demo():
    """Run XPC method enumeration"""
    print("XPC Method Enumerator v1.0")
    print("=" * 60)
    print("SAFETY: Read-only analysis (no XPC connections)")
    print("MEMORY: Processes one binary at a time")
    print("=" * 60)

    engine = XPCMethodEnumerator()
    results = engine.run_analysis()

    print("\n[Results]")
    print("  Services found: %d" % results['services_found'])
    print("  With binary: %d" % results['services_with_binary'])
    print("  Daemons: %d | Agents: %d" % (results['daemons'], results['agents']))
    print("  Total protocols: %d" % results['total_protocols'])
    print("  Total methods: %d" % results['total_methods'])

    if results['top_services']:
        print("\n  TOP XPC SERVICES (by attack surface):")
        for svc in results['top_services'][:15]:
            if svc['score'] > 0:
                print("    [Score %d] %s (%s)" % (
                    svc['score'], svc['name'][:40], svc['type']))
                if svc['protocols']:
                    for p in svc['protocols'][:3]:
                        print("      Protocol: %s (%d methods)" % (p['name'][:40], len(p['methods'])))
                        for m in p['methods'][:5]:
                            print("        - %s" % m[:60])
                if svc['reasons']:
                    print("      Reasons: %s" % ', '.join(svc['reasons'][:4]))

    if engine.findings:
        print("\n  Security Findings:")
        for f in engine.findings[:10]:
            print("    [%s] %s" % (f['severity'], f['detail'][:70]))

    print("\nXPC method enumeration complete")

demo()

