#!/usr/bin/env python3
"""ATS (App Transport Security) Configuration Analyzer for iOS/macOS apps.
Checks Info.plist for insecure ATS exceptions that weaken TLS enforcement."""

import os
import plistlib
import json
import re

class ATSAnalyzer:
    """Analyze App Transport Security configurations."""

    # ATS exception risk levels
    RISK_LEVELS = {
        'NSAllowsArbitraryLoads': ('CRITICAL', 'Disables ATS entirely — all HTTP allowed'),
        'NSAllowsArbitraryLoadsForMedia': ('HIGH', 'Allows HTTP for media — AV content can be intercepted'),
        'NSAllowsArbitraryLoadsInWebContent': ('HIGH', 'Allows HTTP in WKWebView — web content can be MITM'),
        'NSAllowsLocalNetworking': ('MEDIUM', 'Allows unencrypted local network — ok for dev, risky in prod'),
        'NSExceptionAllowsInsecureHTTPLoads': ('HIGH', 'Domain allows HTTP — traffic can be intercepted'),
        'NSExceptionMinimumTLSVersion': ('MEDIUM', 'Allows older TLS — TLS 1.0/1.1 have known weaknesses'),
        'NSExceptionRequiresForwardSecrecy': ('MEDIUM', 'Disables PFS requirement — weaker key exchange'),
        'NSIncludesSubdomains': ('LOW', 'Exception applies to all subdomains — wider attack surface'),
    }

    # Minimum acceptable TLS versions
    TLS_VERSIONS = {
        'TLSv1.0': ('HIGH', 'TLS 1.0 is deprecated (RFC 8996)'),
        'TLSv1.1': ('HIGH', 'TLS 1.1 is deprecated (RFC 8996)'),
        'TLSv1.2': ('LOW', 'TLS 1.2 is acceptable'),
        'TLSv1.3': ('INFO', 'TLS 1.3 is recommended'),
    }

    def __init__(self):
        self.findings = []

    def analyze_plist(self, plist_path):
        """Analyze Info.plist for ATS configuration."""
        with open(plist_path, 'rb') as f:
            try:
                plist = plistlib.load(f)
            except Exception:
                # Try XML format
                f.seek(0)
                plist = plistlib.loads(f.read())

        ats = plist.get('NSAppTransportSecurity', {})
        if not ats:
            self.findings.append({
                'severity': 'INFO',
                'key': 'NSAppTransportSecurity',
                'detail': 'Not configured — ATS defaults apply (secure)',
            })
            return self.findings

        # Check global ATS settings
        for key, (severity, description) in self.RISK_LEVELS.items():
            if ats.get(key):
                self.findings.append({
                    'severity': severity,
                    'key': key,
                    'value': ats[key],
                    'detail': description,
                })

        # Check per-domain exceptions
        exceptions = ats.get('NSExceptionDomains', {})
        for domain, config in exceptions.items():
            for key, value in config.items():
                if key in self.RISK_LEVELS:
                    severity, desc = self.RISK_LEVELS[key]
                    self.findings.append({
                        'severity': severity,
                        'key': f'{domain}.{key}',
                        'value': value,
                        'detail': f'{domain}: {desc}',
                    })
                elif key == 'NSExceptionMinimumTLSVersion':
                    if value in self.TLS_VERSIONS:
                        severity, desc = self.TLS_VERSIONS[value]
                        self.findings.append({
                            'severity': severity,
                            'key': f'{domain}.{key}',
                            'value': value,
                            'detail': f'{domain}: {desc}',
                        })

        return self.findings

    def analyze_directory(self, app_dir):
        """Find and analyze all Info.plist files in an app bundle."""
        results = {}
        for root, dirs, files in os.walk(app_dir):
            for name in files:
                if name == 'Info.plist':
                    path = os.path.join(root, name)
                    try:
                        self.findings = []
                        findings = self.analyze_plist(path)
                        if findings:
                            results[path] = findings
                    except Exception as e:
                        results[path] = [{'severity': 'ERROR', 'detail': str(e)}]
        return results

    def generate_report(self):
        """Generate security report."""
        critical = [f for f in self.findings if f['severity'] == 'CRITICAL']
        high = [f for f in self.findings if f['severity'] == 'HIGH']

        report = {
            'total_findings': len(self.findings),
            'critical': len(critical),
            'high': len(high),
            'findings': self.findings,
            'recommendation': 'Remove NSAllowsArbitraryLoads' if critical else 'Review domain exceptions',
        }
        return report

# Demo
analyzer = ATSAnalyzer()

# Create a sample Info.plist with ATS exceptions
import tempfile
sample_plist = {
    'CFBundleName': 'TestApp',
    'NSAppTransportSecurity': {
        'NSAllowsArbitraryLoads': False,
        'NSExceptionDomains': {
            'api.example.com': {
                'NSExceptionAllowsInsecureHTTPLoads': True,
                'NSExceptionMinimumTLSVersion': 'TLSv1.0',
                'NSIncludesSubdomains': True,
            },
            'cdn.legacy.com': {
                'NSExceptionAllowsInsecureHTTPLoads': True,
                'NSExceptionRequiresForwardSecrecy': False,
            },
        },
    },
}

with tempfile.NamedTemporaryFile(suffix='.plist', delete=False) as f:
    plistlib.dump(sample_plist, f)
    plist_path = f.name

findings = analyzer.analyze_plist(plist_path)
report = analyzer.generate_report()

print('=== ATS Configuration Analysis ===')
print(f'Total findings: {report["total_findings"]}')
print(f'Critical: {report["critical"]}')
print(f'High: {report["high"]}')
print()
for f in findings:
    print(f'  [{f["severity"]:8}] {f["key"]}: {f["detail"]}')
print(f'\nRecommendation: {report["recommendation"]}')
print('ATS analysis complete')

os.unlink(plist_path)

