#!/usr/bin/env python3
"""Mobile Provisioning Profile Analyzer for iOS apps.
Extracts and validates provisioning profiles, entitlements, and certificate chains."""

import os
import subprocess
import plistlib
import json
import re
import hashlib
import tempfile
from datetime import datetime

class ProvisioningAnalyzer:
    """Analyze iOS mobile provisioning profiles."""

    DANGEROUS_ENTITLEMENTS = {
        'get-task-allow': 'Allows debugging — app can be attached with lldb',
        'com.apple.private.security.no-container': 'No sandbox container — full filesystem access',
        'com.apple.private.skip-library-validation': 'Skip library validation — can load unsigned dylibs',
        'platform-application': 'Platform app — bypasses many security checks',
        'com.apple.system-task-ports': 'System task ports — can control other processes',
        'task_for_pid-allow': 'task_for_pid — can get task port of any process',
        'com.apple.private.security.no-sandbox': 'No sandbox — runs outside App Sandbox entirely',
    }

    PROFILE_TYPES = {
        'Development': 'Dev profiles allow debugging, limited devices',
        'Ad Hoc': 'Ad hoc for testing, specific device UDIDs',
        'Enterprise': 'Enterprise (in-house) distribution, any device in org',
        'App Store': 'App Store distribution, no get-task-allow',
    }

    def analyze_profile(self, profile_path):
        """Analyze a .mobileprovision file."""
        findings = []

        # Extract plist from CMS envelope using security tool
        try:
            result = subprocess.run(
                ['security', 'cms', '-D', '-i', profile_path],
                capture_output=True, text=True, timeout=10
            )
            if result.returncode != 0:
                # Fallback: try to extract XML between <plist> tags
                with open(profile_path, 'rb') as f:
                    data = f.read()
                start = data.find(b'<?xml')
                end = data.find(b'</plist>') + len(b'</plist>')
                if start >= 0 and end > start:
                    plist_data = data[start:end]
                    profile = plistlib.loads(plist_data)
                else:
                    return [{'severity': 'ERROR', 'detail': 'Cannot parse profile'}]
            else:
                profile = plistlib.loads(result.stdout.encode())
        except Exception as e:
            return [{'severity': 'ERROR', 'detail': f'Parse error: {e}'}]

        # Basic info
        app_id = profile.get('AppIDName', 'Unknown')
        team = profile.get('TeamName', 'Unknown')
        team_id = profile.get('TeamIdentifier', ['Unknown'])[0]
        name = profile.get('Name', 'Unknown')
        uuid = profile.get('UUID', 'Unknown')
        creation = profile.get('CreationDate', 'Unknown')
        expiration = profile.get('ExpirationDate', 'Unknown')

        findings.append({
            'severity': 'INFO',
            'category': 'profile_info',
            'detail': f'Name: {name}, Team: {team} ({team_id}), UUID: {uuid}',
        })

        # Check expiration
        if isinstance(expiration, datetime):
            if expiration < datetime.now():
                findings.append({
                    'severity': 'HIGH',
                    'category': 'expired',
                    'detail': f'Profile expired on {expiration.isoformat()}',
                })
            else:
                days_left = (expiration - datetime.now()).days
                if days_left < 30:
                    findings.append({
                        'severity': 'MEDIUM',
                        'category': 'expiring_soon',
                        'detail': f'Profile expires in {days_left} days',
                    })

        # Check profile type
        provisions_all = profile.get('ProvisionsAllDevices', False)
        devices = profile.get('ProvisionedDevices', [])

        if provisions_all:
            findings.append({
                'severity': 'HIGH',
                'category': 'enterprise',
                'detail': 'Enterprise profile — provisions ALL devices (sideloading risk)',
            })
        elif devices:
            findings.append({
                'severity': 'INFO',
                'category': 'devices',
                'detail': f'Provisioned for {len(devices)} specific devices',
            })

        # Check entitlements
        entitlements = profile.get('Entitlements', {})
        for key, value in entitlements.items():
            if key in self.DANGEROUS_ENTITLEMENTS and value:
                findings.append({
                    'severity': 'CRITICAL' if 'no-sandbox' in key or 'no-container' in key else 'HIGH',
                    'category': 'dangerous_entitlement',
                    'detail': f'{key}: {self.DANGEROUS_ENTITLEMENTS[key]}',
                })
            elif key == 'get-task-allow' and value:
                findings.append({
                    'severity': 'HIGH',
                    'category': 'debuggable',
                    'detail': 'get-task-allow=true — app can be debugged (not App Store)',
                })

        # Check for wildcard app ID
        app_id_str = entitlements.get('application-identifier', '')
        if '*' in str(app_id_str):
            findings.append({
                'severity': 'MEDIUM',
                'category': 'wildcard_appid',
                'detail': f'Wildcard app ID: {app_id_str} — less restrictive',
            })

        return findings, profile

    def scan_directory(self, directory):
        """Scan directory for .mobileprovision files."""
        results = {}
        for root, dirs, files in os.walk(directory):
            for name in files:
                if name.endswith('.mobileprovision'):
                    path = os.path.join(root, name)
                    findings, _ = self.analyze_profile(path)
                    results[path] = findings
        return results

# Demo with installed profiles
analyzer = ProvisioningAnalyzer()

print('=== Mobile Provisioning Profile Analyzer ===')
print()

# Scan for installed profiles
profile_dirs = [
    os.path.expanduser('~/Library/MobileDevice/Provisioning Profiles'),
    '/Library/MobileDevice/Provisioning Profiles',
]

total_profiles = 0
total_findings = 0

for pdir in profile_dirs:
    if os.path.exists(pdir):
        profiles = [f for f in os.listdir(pdir) if f.endswith('.mobileprovision')]
        print(f'Directory: {pdir}')
        print(f'  Profiles found: {len(profiles)}')

        for pf in profiles[:5]:
            path = os.path.join(pdir, pf)
            findings, profile = analyzer.analyze_profile(path)
            total_profiles += 1
            total_findings += len(findings)

            name = profile.get('Name', 'Unknown') if profile else pf
            print(f'\n  Profile: {name}')
            for f in findings:
                print(f'    [{f["severity"]:8}] {f["detail"][:80]}')

if total_profiles == 0:
    print('  No provisioning profiles found (expected on non-dev machines)')
    # Show capabilities
    print('\n[*] Profile Types:')
    for ptype, desc in analyzer.PROFILE_TYPES.items():
        print(f'    {ptype}: {desc}')
    print('\n[*] Dangerous Entitlements to check:')
    for ent, desc in list(analyzer.DANGEROUS_ENTITLEMENTS.items())[:5]:
        print(f'    {ent}: {desc}')

print(f'\nTotal: {total_profiles} profiles, {total_findings} findings')
print('Provisioning profile analysis complete')
